export const DrumMachine: React.FC<DrumMachineProps> = ({
  isPlaying,
  onPlayToggle,
  bpm,
  onBpmChange,
  pattern,
  selectedTrack,
  onTrackSelect,
  onStepToggle,
  currentStep
}) => {
  const currentTheme = TRACK_STYLES[selectedTrack];

  return (
    <div className="bg-gray-800/50 rounded-xl border border-gray-700/50 p-4 flex flex-col items-center shadow-lg backdrop-blur-sm gap-6">
      {/* Top Controls: Play/BPM and Track Selectors combined */}
