      <div className="w-full bg-gray-900/30 border-t border-gray-800 p-6 rounded-b-lg overflow-x-auto">
        <div className="flex flex-row gap-3 justify-center min-w-max px-4">
          {pattern[selectedTrack].map((step, index) => {
            const isStepOn = step === 1;
            const isPlayingStep = index === currentStep;
            const stepGroup = Math.floor(index / 4);

            let stepClasses = 'w-8 h-12 rounded transition-all duration-150 flex-shrink-0 ';

            if (isStepOn) {
                stepClasses += isPlayingStep
                    ? `${currentTheme.stepOnPlaying} ring-2 ring-white z-10 `
                    : `${currentTheme.stepOn} `;
            } else {
                 stepClasses += isPlayingStep
                    ? `${currentTheme.stepOffPlaying} scale-105 `
                    : (stepGroup % 2 === 0)
                        ? 'bg-gray-700/50 hover:bg-gray-600/50 '
                        : 'bg-gray-800/50 hover:bg-gray-700/50 ';
            }

            return (
              <button
                key={`${selectedTrack}-${index}`}
                onClick={() => onStepToggle(selectedTrack, index)}
                className={stepClasses}
                aria-label={`Step ${index + 1} for ${selectedTrack}`}
              />
            );
          })}
        </div>
      </div>
    </div>
  );
};

