export const Synth: React.FC = () => {
  const [params, setParams] = useState<SynthParameters>(DEFAULT_SYNTH_PARAMS);
  const [midiStatus, setMidiStatus] = useState<string>('Not initialized. Click to start.');
  const [isStarted, setIsStarted] = useState(false);
  const [activeNotes, setActiveNotes] = useState<Set<number>>(new Set());

  // Drum Machine State
  const [banks, setBanks] = useState<StepSequencePattern[]>(() => 
    Array(4).fill(null).map(() => JSON.parse(JSON.stringify(DEFAULT_DRUM_PATTERN)))
  );
  const [currentBankIndex, setCurrentBankIndex] = useState<number>(0);
  const drumPattern = banks[currentBankIndex];

  const [selectedTrack, setSelectedTrack] = useState<DrumTrackName>('kick');
  const [isDrumMachinePlaying, setIsDrumMachinePlaying] = useState(false);
  const [bpm, setBpm] = useState(DEFAULT_BPM);
  const [currentStep, setCurrentStep] = useState<number | null>(null);

  const audioEngine = useRef<AudioEngine | null>(null);
  const drumMachineEngine = useRef<DrumMachineEngine | null>(null);

  const handleStart = useCallback(async () => {
    if (isStarted) return;

    const engine = new AudioEngine(DEFAULT_SYNTH_PARAMS);
    await engine.start();
    const audioContext = engine.getContext();
    if (!audioContext) {
        setMidiStatus('Failed to initialize Audio Context.');
        return;
    }
    audioEngine.current = engine;

    drumMachineEngine.current = new DrumMachineEngine(audioContext, (step) => setCurrentStep(step));
    drumMachineEngine.current.setPattern(drumPattern);


    setIsStarted(true);
    setMidiStatus('Initializing MIDI...');

    try {
      const midiAccess = await navigator.requestMIDIAccess();
      setMidiStatus('MIDI Access Granted');

      if (midiAccess.inputs.size > 0) {
        const devices: string[] = [];
        midiAccess.inputs.forEach((input) => {
          devices.push(input.name || 'Unknown Device');
          input.onmidimessage = (e) => handleMidiMessage(e);
        });
        setMidiStatus(`Connected to: ${devices.join(', ')}`);
      } else {
        setMidiStatus('No MIDI input devices found.');
      }

      midiAccess.onstatechange = (event: Event) => {
          const port = (event as MIDIConnectionEvent).port;
          if (port.type === 'input') {
              const deviceName = port.name || 'Unknown Device';
              if (port.state === 'connected') {
                  setMidiStatus(`MIDI device connected: ${deviceName}`);
              } else {
                  setMidiStatus(`MIDI device disconnected: ${deviceName}`);
              }
          }
      };

    } catch (error) {
      console.error('MIDI Access Denied:', error);
      setMidiStatus('MIDI access denied by user.');
    }
  }, [isStarted]);

  useEffect(() => {
    if (audioEngine.current) {
      audioEngine.current.updateParams(params);
    }
  }, [params]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setBpm(bpm);
      }
  }, [bpm]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setPattern(drumPattern);
      }
  }, [drumPattern]);

  const handleStepToggle = (track: DrumTrackName, stepIndex: number) => {
    const newBanks = [...banks];
    const currentPattern = { ...newBanks[currentBankIndex] };
    const newTrackPattern = [...currentPattern[track]];

    const isOn = newTrackPattern[stepIndex] === 0;
    newTrackPattern[stepIndex] = isOn ? 1 : 0;

    currentPattern[track] = newTrackPattern;
    newBanks[currentBankIndex] = currentPattern;

    setBanks(newBanks);

    if (isOn && drumMachineEngine.current) {
      drumMachineEngine.current.playSound(track);
    }
  };


  const handleMidiMessage = (message: MIDIMessageEvent) => {
    if (!audioEngine.current) return;

    const [command, note, velocity] = message.data;
    if (command === 144 && velocity > 0) {
      audioEngine.current.noteOn(note, velocity);
      setActiveNotes(prev => new Set(prev).add(note));
    } else if (command === 128 || (command === 144 && velocity === 0)) {
      audioEngine.current.noteOff(note);
      setActiveNotes(prev => {
        const newSet = new Set(prev);
        newSet.delete(note);
        return newSet;
      });
    }
  };

  const handleNoteOn = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOn(note, 100);
    setActiveNotes(prev => new Set(prev).add(note));
  };

  const handleNoteOff = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOff(note);
    setActiveNotes(prev => {
      const newSet = new Set(prev);
      newSet.delete(note);
      return newSet;
    });
  };

  const setOscWaveform = (osc: 'osc1' | 'osc2', waveform: Waveform) => {
    setParams(p => ({ ...p, [osc]: { ...p[osc], waveform } }));
  };

  const handlePlayToggle = () => {
      if (!drumMachineEngine.current) return;
      const nextIsPlaying = !isDrumMachinePlaying;
      setIsDrumMachinePlaying(nextIsPlaying);
      if (nextIsPlaying) {
          drumMachineEngine.current.play();
      } else {
          drumMachineEngine.current.stop();
          setCurrentStep(null);
      }
  };

  const renderWaveformSelector = (osc: 'osc1' | 'osc2') => (
    <div className="flex items-center space-x-2 bg-[#111] p-1 rounded-sm border border-[#222]">
      {(['sine', 'triangle', 'sawtooth', 'square'] as Waveform[]).map(w => {
        const isActive = params[osc].waveform === w;
        const Icon = { sine: SineIcon, triangle: TriangleIcon, sawtooth: SawtoothIcon, square: SquareIcon }[w];
        return (
          <button 
            key={w} 
            onClick={() => setOscWaveform(osc, w)} 
            className={`p-2 rounded-sm transition-all duration-100 relative group
                ${isActive 
                    ? 'bg-[#333] text-white shadow-[0_0_5px_rgba(255,255,255,0.2)] border border-gray-600' 
                    : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                }`}
          >
            <Icon className="w-5 h-5"/>
            {/* LED Indicator */}
            {isActive && <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-1 h-1 bg-white rounded-full shadow-[0_0_4px_white]"></div>}
          </button>
        );
      })}
    </div>
  );

  if (!isStarted) {
    return (
        <div className="flex flex-col items-center justify-center bg-[#1a1a1a] border border-[#333] rounded-sm p-16 shadow-2xl">
            <h2 className="text-2xl font-bold text-white mb-2 tracking-wider">SYSTEM STANDBY</h2>
            <p className="text-gray-500 mb-8 font-mono text-xs">{midiStatus}</p>
            <button
                onClick={handleStart}
                className="px-8 py-3 bg-[#222] text-gray-200 border border-gray-600 font-bold text-sm tracking-widest rounded-sm hover:bg-gray-200 hover:text-black hover:border-white transition-all duration-200 shadow-lg"
            >
                INITIALIZE ENGINE
            </button>
        </div>
    );
  }

  return (
    <div className="space-y-8">

      {/* Top Section: Oscillators, Filter, Envelopes */}
      <div className="flex flex-col xl:flex-row gap-8 items-stretch">

        {/* Left: Oscillators */}
        <Panel title="VCO" className="flex-1 justify-center min-h-[300px]">
             <div className="flex flex-col gap-10 py-4 w-full max-w-2xl">
                <div className="flex flex-col md:flex-row items-center justify-around gap-12 border-b border-[#222] pb-8">
                    <div className="flex flex-col items-center gap-3">
                        <span className="text-gray-500 text-[10px] font-mono tracking-widest">OSCILLATOR 1</span>
                        {renderWaveformSelector('osc1')}
                    </div>
                     <div className="flex flex-col items-center gap-3">
                        <span className="text-gray-500 text-[10px] font-mono tracking-widest">OSCILLATOR 2</span>
                        {renderWaveformSelector('osc2')}
                    </div>
                </div>
                <div className="flex items-center justify-center gap-16 pt-2">
                   <Knob label="Mix" value={params.oscMix} min={0} max={1} onChange={v => setParams(p => ({ ...p, oscMix: v }))} />
                   <Knob label="Pitch" value={params.osc2.detune} min={-100} max={100} onChange={v => setParams(p => ({ ...p, osc2: { ...p.osc2, detune: v } }))} />
                </div>
            </div>
        </Panel>

        {/* Right: Filter & Envelopes Group */}
        <div className="flex flex-col sm:flex-row gap-8 shrink-0 xl:w-[500px]">

            {/* Filter */}
            <Panel title="VCF" className="sm:w-1/3 justify-between">
                <div className="flex flex-col gap-6 h-full justify-center py-2">
                    <Knob label="Cutoff" value={params.filter.cutoff} min={20} max={20000} onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, cutoff: v } }))} />
                    <Knob label="Resonance" value={params.filter.resonance} min={0} max={40} onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, resonance: v } }))} />
                    <Knob label="EG Int" value={params.filterEnvelope.amount} min={0} max={10000} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, amount: v } }))} />
                </div>
            </Panel>

            {/* Envelopes */}
            <div className="flex flex-col gap-8 sm:w-2/3">
                <Panel title="AMP EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        <Knob label="Attack" value={params.ampEnvelope.attack} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.ampEnvelope.decay} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.ampEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, sustain: v } }))} />
                        <Knob label="Release" value={params.ampEnvelope.release} min={0.001} max={5} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, release: v } }))} />
                    </div>
                </Panel>

                <Panel title="FILTER EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        <Knob label="Attack" value={params.filterEnvelope.attack} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.filterEnvelope.decay} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.filterEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, sustain: v } }))} />
                        <Knob label="Release" value={params.filterEnvelope.release} min={0.001} max={5} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, release: v } }))} />
                    </div>
                </Panel>
            </div>
        </div>

      </div>

      <DrumMachine
        isPlaying={isDrumMachinePlaying}
        onPlayToggle={handlePlayToggle}
        bpm={bpm}
        onBpmChange={setBpm}
        pattern={drumPattern}
        selectedTrack={selectedTrack}
        onTrackSelect={setSelectedTrack}
        onStepToggle={handleStepToggle}
        currentStep={currentStep}
        currentBank={currentBankIndex}
        onBankSelect={setCurrentBankIndex}
       />

      <div className="bg-[#1a1a1a] rounded-sm border-t-4 border-[#111] shadow-2xl">
        <Keyboard onNoteOn={handleNoteOn} onNoteOff={handleNoteOff} activeNotes={activeNotes} />
        <div className="bg-[#0a0a0a] text-center text-[10px] text-gray-600 py-1 font-mono uppercase tracking-widest">{midiStatus}</div>
      </div>
    </div>
  );
};

import React from 'react';
import { Knob } from './Knob';
import { StepSequencePattern, DrumTrackName } from '../types';
import { DRUM_TRACKS } from '../constants';

interface DrumMachineProps {
  isPlaying: boolean;
  onPlayToggle: () => void;
  bpm: number;
  onBpmChange: (bpm: number) => void;
  pattern: StepSequencePattern;
  selectedTrack: DrumTrackName;
  onTrackSelect: (track: DrumTrackName) => void;
  onStepToggle: (track: DrumTrackName, stepIndex: number) => void;
  currentStep: number | null;
  currentBank: number;
  onBankSelect: (bankIndex: number) => void;
}

const TRACK_STYLES = {
  kick: {
    active: 'bg-blue-900 border-blue-500 text-blue-100 shadow-[0_0_10px_rgba(59,130,246,0.5)]',
    inactive: 'bg-[#222] border-[#333] text-gray-500 hover:text-gray-300 hover:border-gray-500',
    stepOn: 'bg-blue-600 shadow-[0_0_8px_rgba(37,99,235,0.6)]',
    stepOnPlaying: 'bg-blue-400 shadow-[0_0_12px_rgba(96,165,250,0.8)]',
  },
  snare: {
    active: 'bg-red-900 border-red-500 text-red-100 shadow-[0_0_10px_rgba(239,68,68,0.5)]',
    inactive: 'bg-[#222] border-[#333] text-gray-500 hover:text-gray-300 hover:border-gray-500',
    stepOn: 'bg-red-600 shadow-[0_0_8px_rgba(220,38,38,0.6)]',
    stepOnPlaying: 'bg-red-400 shadow-[0_0_12px_rgba(248,113,113,0.8)]',
  },
  hihat: {
    active: 'bg-green-900 border-green-500 text-green-100 shadow-[0_0_10px_rgba(34,197,94,0.5)]',
    inactive: 'bg-[#222] border-[#333] text-gray-500 hover:text-gray-300 hover:border-gray-500',
    stepOn: 'bg-green-600 shadow-[0_0_8px_rgba(22,163,74,0.6)]',
    stepOnPlaying: 'bg-green-400 shadow-[0_0_12px_rgba(74,222,128,0.8)]',
  },
  crash: {
    active: 'bg-gray-700 border-gray-400 text-white shadow-[0_0_10px_rgba(255,255,255,0.4)]',
    inactive: 'bg-[#222] border-[#333] text-gray-500 hover:text-gray-300 hover:border-gray-500',
    stepOn: 'bg-gray-400 shadow-[0_0_8px_rgba(255,255,255,0.5)]',
    stepOnPlaying: 'bg-white shadow-[0_0_12px_rgba(255,255,255,0.8)]',
  }
};

export const DrumMachine: React.FC<DrumMachineProps> = ({
  isPlaying,
  onPlayToggle,
  bpm,
  onBpmChange,
  pattern,
  selectedTrack,
  onTrackSelect,
  onStepToggle,
  currentStep,
  currentBank,
  onBankSelect
}) => {
  const currentTheme = TRACK_STYLES[selectedTrack];

  return (
    <div className="relative bg-[#1a1a1a] rounded-sm border border-[#333] p-6 flex flex-col items-center shadow-xl">
       {/* Hardware Screw aesthetic */}
      <div className="absolute top-2 left-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-45"></div></div>
      <div className="absolute top-2 right-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-12"></div></div>

      <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mb-6 border-b border-gray-700 pb-1 px-2 w-full text-center">SEQUENCER</h3>

      {/* Top Controls: Play/BPM and Track Selectors combined */}
      <div className="w-full flex flex-col xl:flex-row items-center justify-between gap-8 px-2 py-2">

        {/* Play & BPM */}
        <div className="flex items-center gap-8 shrink-0">
          <button
            onClick={onPlayToggle}
            className={`w-20 h-10 text-xs font-bold font-mono tracking-widest rounded-sm border-2 transition-all duration-100 ${
              isPlaying
                ? 'bg-[#333] border-white text-white shadow-[0_0_8px_rgba(255,255,255,0.6)]'
                : 'bg-[#222] border-[#444] text-gray-400 hover:bg-[#333] hover:text-gray-200'
            }`}
          >
            {isPlaying ? 'STOP' : 'PLAY'}
          </button>
          <Knob label="Tempo" value={bpm} min={60} max={180} onChange={onBpmChange} />
        </div>

        {/* Track Selectors - Styled like backlit rubber buttons */}
        <div className="flex flex-wrap gap-2 justify-center">
          {DRUM_TRACKS.map((track) => {
            const isActive = track === selectedTrack;
            const style = TRACK_STYLES[track];
            return (
              <button
                key={track}
                onClick={() => onTrackSelect(track)}
                className={`px-3 py-4 font-bold text-[10px] uppercase rounded-sm transition-all duration-100 w-20 tracking-wider border-b-2 ${
                  isActive ? style.active : style.inactive
                }`}
              >
                {track}
              </button>
            );
          })}
        </div>

        {/* Bank Selectors */}
        <div className="flex flex-col items-center gap-2 shrink-0">
          <span className="text-[9px] text-gray-500 uppercase font-mono tracking-widest">Bank</span>
          <div className="flex gap-2 bg-[#111] p-1 rounded-sm border border-[#222]">
            {[0, 1, 2, 3].map((bankIndex) => (
              <button
                key={bankIndex}
                onClick={() => onBankSelect(bankIndex)}
                className={`w-8 h-6 rounded-sm font-bold text-xs transition-all duration-100 relative ${
                  currentBank === bankIndex
                    ? 'bg-purple-900/80 text-white shadow-[0_0_5px_rgba(168,85,247,0.5)] border border-purple-500'
                    : 'bg-[#222] text-gray-600 hover:text-gray-400 border border-[#333]'
                }`}
              >
                {bankIndex + 1}
              </button>
            ))}
          </div>
        </div>

      </div>

      {/* Step Sequencer Grid - Styled like LED row */}
      <div className="w-full bg-[#111] border-t border-b border-[#333] py-6 mt-4 flex justify-center relative shadow-inner">
        <div className="absolute top-0 left-0 w-full h-[1px] bg-[#000]"></div>
        <div className="flex flex-row gap-2 md:gap-3 justify-center min-w-max px-4">
          {pattern[selectedTrack].map((step, index) => {
            const isStepOn = step === 1;
            const isPlayingStep = index === currentStep;
            const stepGroup = Math.floor(index / 4);
            const isDownbeat = index % 4 === 0;

            let baseClass = "w-6 h-10 md:w-8 md:h-12 rounded-[1px] transition-all duration-75 relative border-b-2 ";

            // Background & Border colors
            if (isStepOn) {
                baseClass += isPlayingStep ? currentTheme.stepOnPlaying + " border-white " : currentTheme.stepOn + " border-black/50 ";
            } else {
                 baseClass += isPlayingStep
                    ? 'bg-[#444] border-white '
                    : (stepGroup % 2 === 0)
                        ? 'bg-[#222] border-[#111] hover:bg-[#2a2a2a] '
                        : 'bg-[#1e1e1e] border-[#111] hover:bg-[#262626] ';
            }

            return (
              <button
                key={`${selectedTrack}-${index}`}
                onClick={() => onStepToggle(selectedTrack, index)}
                className={baseClass}
                aria-label={`Step ${index + 1} for ${selectedTrack}`}
              >
                {/* LED bulb effect inside the button */}
                <div className={`absolute top-1 left-1/2 -translate-x-1/2 w-3 h-1 rounded-full ${isStepOn ? 'bg-white/80 shadow-[0_0_4px_white]' : 'bg-black/30'}`}></div>

                {/* Step Number */}
                {isDownbeat && <span className="absolute bottom-1 left-1/2 -translate-x-1/2 text-[8px] text-gray-600 font-mono">{index + 1}</span>}
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { KEYBOARD_LAYOUT } from '../constants';

interface KeyboardProps {
  onNoteOn: (note: number) => void;
  onNoteOff: (note: number) => void;
  activeNotes: Set<number>;
}

export const Keyboard: React.FC<KeyboardProps> = ({ onNoteOn, onNoteOff, activeNotes }) => {
  const [pressedMouseNotes, setPressedMouseNotes] = useState<Set<number>>(new Set());

  const whiteKeys = KEYBOARD_LAYOUT.filter(k => k.type === 'white');
  const blackKeys = KEYBOARD_LAYOUT.filter(k => k.type === 'black');

  const handleMouseDown = (note: number) => {
    onNoteOn(note);
    setPressedMouseNotes(prev => new Set(prev).add(note));
  };

  const handleMouseUp = (note: number) => {
    onNoteOff(note);
    setPressedMouseNotes(prev => {
        const newSet = new Set(prev);
        newSet.delete(note);
        return newSet;
    });
  };

  const handleMouseLeave = (note: number) => {
    if (pressedMouseNotes.has(note)) {
      handleMouseUp(note);
    }
  };

  return (
    <div className="relative w-full h-40 select-none bg-[#0a0a0a] p-1 shadow-inner">
      {/* White Keys */}
      <div className="absolute top-1 left-1 right-1 bottom-1 flex gap-[1px]">
        {whiteKeys.map(key => {
          const isActive = activeNotes.has(key.midi);
          return (
            <div
              key={key.midi}
              onMouseDown={() => handleMouseDown(key.midi)}
              onMouseUp={() => handleMouseUp(key.midi)}
              onMouseLeave={() => handleMouseLeave(key.midi)}
              className={`flex-1 h-full rounded-b-sm transition-colors duration-75 relative ${
                isActive ? 'bg-gray-300 shadow-inner' : 'bg-[#e5e5e5] hover:bg-white'
              }`}
            >
                {/* Key shadow at bottom */}
                <div className="absolute bottom-0 w-full h-2 bg-black/10 rounded-b-sm pointer-events-none"></div>
            </div>
          );
        })}
      </div>
      {/* Black Keys */}
      <div className="absolute top-1 left-1 right-1 h-[60%] flex pointer-events-none px-[1px]">
        {whiteKeys.map((key) => {
            const blackKey = blackKeys.find(bk => bk.midi === key.midi + 1);
            if (!blackKey) {
                 return <div key={`space-${key.midi}`} className="flex-1" />;
            }

            return (
              <div key={`container-${key.midi}`} className="flex-1 flex">
                <div className="h-full w-2/3" />
                <div className="h-full w-2/3 pointer-events-auto -mx-[33%] z-10">
                    <div
                        key={blackKey.midi}
                        onMouseDown={(e) => { e.stopPropagation(); handleMouseDown(blackKey.midi); }}
                        onMouseUp={(e) => { e.stopPropagation(); handleMouseUp(blackKey.midi); }}
                        onMouseLeave={(e) => { e.stopPropagation(); handleMouseLeave(blackKey.midi); }}
                        className={`h-full w-full rounded-b-sm border-x border-b border-black/50 transition-colors duration-75 relative ${
                            activeNotes.has(blackKey.midi) ? 'bg-gray-800' : 'bg-[#111] hover:bg-[#222] shadow-[2px_2px_4px_rgba(0,0,0,0.3)]'
                        }`}
                    >
                         {/* Shine on black key */}
                         <div className="absolute top-0 left-[10%] w-[80%] h-[90%] bg-gradient-to-b from-gray-700/30 to-transparent rounded-sm pointer-events-none"></div>
                    </div>
                </div>
                <div className="h-full w-2/3" />
              </div>
            );
        })}
      </div>
    </div>
  );
};

import { StepSequencePattern, DrumTrackName } from '../types';

export class DrumMachineEngine {
  private audioContext: AudioContext;
  private isPlaying = false;
  private bpm = 120;
  private pattern: StepSequencePattern | null = null;
  private currentStep = 0;
  private timerId?: number;
  private lookahead = 25.0; // ms
  private scheduleAheadTime = 0.1; // s
  private nextNoteTime = 0.0;
  private onStepChange?: (step: number) => void;

  // New features
  private swing = 0; // 0 to 100
  private trackPitches: Record<DrumTrackName, number> = {
      kick: 0,
      snare: 0,
      hihat: 0,
      crash: 0
  };

  constructor(audioContext: AudioContext, onStepChange?: (step: number) => void) {
    this.audioContext = audioContext;
    this.onStepChange = onStepChange;
  }

  public setSwing(value: number) {
      this.swing = value;
  }

  public setTrackPitch(track: DrumTrackName, pitch: number) {
      this.trackPitches[track] = pitch;
  }

  private getRate(track: DrumTrackName): number {
      const semitones = this.trackPitches[track];
      return Math.pow(2, semitones / 12);
  }

  private createKick(time: number) {
    const rate = this.getRate('kick');
    const osc = this.audioContext.createOscillator();
    const gain = this.audioContext.createGain();

    const startFreq = 150 * rate;
    const endFreq = 0.01; // End freq usually doesn't need scaling as it hits 0, but for pitch feel it's mostly the transient

    osc.frequency.setValueAtTime(startFreq, time);
    osc.frequency.exponentialRampToValueAtTime(endFreq, time + 0.1);

    gain.gain.setValueAtTime(1, time);
    gain.gain.exponentialRampToValueAtTime(0.01, time + 0.1);

    osc.connect(gain);
    gain.connect(this.audioContext.destination);

    osc.start(time);
    osc.stop(time + 0.15);
  }

  private createSnare(time: number) {
    const rate = this.getRate('snare');
    const noise = this.audioContext.createBufferSource();
    const buffer = this.audioContext.createBuffer(1, this.audioContext.sampleRate * 0.2, this.audioContext.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < data.length; i++) {
      data[i] = Math.random() * 2 - 1;
    }
    noise.buffer = buffer;
    noise.playbackRate.value = rate;

    const noiseFilter = this.audioContext.createBiquadFilter();
    noiseFilter.type = 'highpass';
    noiseFilter.frequency.value = 1000 * rate;

    const noiseGain = this.audioContext.createGain();
    noiseGain.gain.setValueAtTime(0.5, time);
    noiseGain.gain.exponentialRampToValueAtTime(0.01, time + 0.15);

    noise.connect(noiseFilter).connect(noiseGain).connect(this.audioContext.destination);

    const osc = this.audioContext.createOscillator();
    osc.type = 'triangle';
    osc.frequency.value = 100 * rate;
    const oscGain = this.audioContext.createGain();
    oscGain.gain.setValueAtTime(0.7, time);
    oscGain.gain.exponentialRampToValueAtTime(0.01, time + 0.1);

    osc.connect(oscGain).connect(this.audioContext.destination);

    noise.start(time);
    osc.start(time);
    noise.stop(time + 0.2);
    osc.stop(time + 0.15);
  }

  private createHihat(time: number) {
    const rate = this.getRate('hihat');
    const noise = this.audioContext.createBufferSource();
    const buffer = this.audioContext.createBuffer(1, this.audioContext.sampleRate * 0.1, this.audioContext.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < data.length; i++) {
      data[i] = Math.random() * 2 - 1;
    }
    noise.buffer = buffer;
    noise.playbackRate.value = rate;

    const noiseFilter = this.audioContext.createBiquadFilter();
    noiseFilter.type = 'highpass';
    noiseFilter.frequency.value = 7000 * rate;

    const noiseGain = this.audioContext.createGain();
    noiseGain.gain.setValueAtTime(0.3, time);
    noiseGain.gain.exponentialRampToValueAtTime(0.01, time + 0.05);

    noise.connect(noiseFilter).connect(noiseGain).connect(this.audioContext.destination);

    noise.start(time);
    noise.stop(time + 0.1);
  }

  private createCrash(time: number) {
    const rate = this.getRate('crash');
    const noise = this.audioContext.createBufferSource();
    const bufferSize = this.audioContext.sampleRate * 1.5; 
    const buffer = this.audioContext.createBuffer(1, bufferSize, this.audioContext.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
    }
    noise.buffer = buffer;
    noise.playbackRate.value = rate;

    const highpass = this.audioContext.createBiquadFilter();
    highpass.type = "highpass";
    highpass.frequency.setValueAtTime(3000 * rate, time); 

    const gain = this.audioContext.createGain();
    gain.gain.setValueAtTime(0.4, time);
    gain.gain.exponentialRampToValueAtTime(0.001, time + 1.2);

    noise.connect(highpass).connect(gain).connect(this.audioContext.destination);

    noise.start(time);
    noise.stop(time + 1.5);
  }

  public playSound(track: DrumTrackName) {
      // Immediate playback uses current time
      const now = this.audioContext.currentTime;
      switch(track) {
          case 'kick': this.createKick(now); break;
          case 'snare': this.createSnare(now); break;
          case 'hihat': this.createHihat(now); break;
          case 'crash': this.createCrash(now); break;
      }
  }

  private scheduleNextNote() {
    if (!this.pattern) return;
    const secondsPerBeat = 60.0 / this.bpm;
    const secondsPer16thNote = secondsPerBeat / 4;

    // Apply swing to odd steps (1, 3, 5...)
    // Swing 0-100 maps to delaying the offbeat by up to a certain fraction of the 16th note
    // 50% swing is often considered "triplet feel" which is 2/3 : 1/3 ratio.
    // Straight is 1/2 : 1/2.
    // Let's implement a delay offset.
    const isOffbeat = this.currentStep % 2 === 1;
    const swingFactor = this.swing / 100; // 0 to 1
    // Max delay typically around 1/3 of the step duration for triplet feel
    const swingDelay = isOffbeat ? (swingFactor * (secondsPer16thNote / 2)) : 0;

    const playTime = this.nextNoteTime + swingDelay;

    if (this.pattern.kick[this.currentStep]) this.createKick(playTime);
    if (this.pattern.snare[this.currentStep]) this.createSnare(playTime);
    if (this.pattern.hihat[this.currentStep]) this.createHihat(playTime);
    if (this.pattern.crash[this.currentStep]) this.createCrash(playTime);

    // Schedule UI update
    // We use setTimeout here because the audio is scheduled ahead. 
    // Ideally we'd use a requestAnimationFrame loop synced to audio context time for visual precision,
    // but looking at `this.nextNoteTime - this.audioContext.currentTime` gives us the delay for UI.
    if (this.onStepChange) {
        const timeUntilNote = Math.max(0, playTime - this.audioContext.currentTime);
        setTimeout(() => {
            if (this.isPlaying && this.onStepChange) {
                this.onStepChange(this.currentStep);
            }
        }, timeUntilNote * 1000);
    }

    // Advance grid time by a straight 16th note
    this.nextNoteTime += secondsPer16thNote;
    this.currentStep = (this.currentStep + 1) % 16;
  }

  private scheduler() {
    // schedule notes for the next `scheduleAheadTime` seconds
    while (this.nextNoteTime < this.audioContext.currentTime + this.scheduleAheadTime) {
      this.scheduleNextNote();
    }
    this.timerId = window.setTimeout(this.scheduler.bind(this), this.lookahead);
  }

  public play() {
    if (this.isPlaying || !this.pattern) return;

    if (this.audioContext.state === 'suspended') {
        this.audioContext.resume();
    }

    this.isPlaying = true;
    this.currentStep = 0;
    this.nextNoteTime = this.audioContext.currentTime + 0.05; // Give a tiny bit of lead time
    this.scheduler();
  }

  public stop() {
    if (!this.isPlaying) return;
    this.isPlaying = false;
    window.clearTimeout(this.timerId);
     if (this.onStepChange) {
      this.onStepChange(-1); 
    }
  }

  public setBpm(newBpm: number) {
      this.bpm = newBpm;
  }

  public setPattern(pattern: StepSequencePattern) {
      this.pattern = pattern;
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SynthParameters, Waveform, StepSequencePattern, DrumTrackName } from '../types';
import { AudioEngine } from '../services/AudioEngine';
import { DrumMachineEngine } from '../services/DrumMachineEngine';
import { Knob } from './Knob';
import { Keyboard } from './Keyboard';
import { DrumMachine } from './DrumMachine';
import { DEFAULT_SYNTH_PARAMS, DEFAULT_BPM, DEFAULT_DRUM_PATTERN } from '../constants';
import { SineIcon, SawtoothIcon, SquareIcon, TriangleIcon } from './Icon';

interface PanelProps {
  title: string;
  children: React.ReactNode;
  className?: string;
}

const Panel: React.FC<PanelProps> = ({ title, children, className = "" }) => (
  <div className={`relative bg-[#1a1a1a] rounded-sm border border-[#333] p-6 flex flex-col items-center shadow-xl ${className}`}>
    {/* Hardware Screw aesthetic */}
    <div className="absolute top-2 left-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-45"></div></div>
    <div className="absolute top-2 right-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-12"></div></div>
    <div className="absolute bottom-2 left-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-90"></div></div>
    <div className="absolute bottom-2 right-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-[-45deg]"></div></div>

    <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mb-6 border-b border-gray-700 pb-1 px-2">{title}</h3>
    {children}
  </div>
);

export const Synth: React.FC = () => {
  const [params, setParams] = useState<SynthParameters>(DEFAULT_SYNTH_PARAMS);
  const [midiStatus, setMidiStatus] = useState<string>('Not initialized. Click to start.');
  const [isStarted, setIsStarted] = useState(false);
  const [activeNotes, setActiveNotes] = useState<Set<number>>(new Set());

  // Drum Machine State
  const [banks, setBanks] = useState<StepSequencePattern[]>(() => 
    Array(4).fill(null).map(() => JSON.parse(JSON.stringify(DEFAULT_DRUM_PATTERN)))
  );
  const [currentBankIndex, setCurrentBankIndex] = useState<number>(0);
  const drumPattern = banks[currentBankIndex];

  const [selectedTrack, setSelectedTrack] = useState<DrumTrackName>('kick');
  const [isDrumMachinePlaying, setIsDrumMachinePlaying] = useState(false);
  const [bpm, setBpm] = useState(DEFAULT_BPM);
  const [swing, setSwing] = useState(0);
  const [drumPitches, setDrumPitches] = useState<Record<DrumTrackName, number>>({
      kick: 0,
      snare: 0,
      hihat: 0,
      crash: 0
  });
  const [currentStep, setCurrentStep] = useState<number | null>(null);

  const audioEngine = useRef<AudioEngine | null>(null);
  const drumMachineEngine = useRef<DrumMachineEngine | null>(null);

  const handleStart = useCallback(async () => {
    if (isStarted) return;

    const engine = new AudioEngine(DEFAULT_SYNTH_PARAMS);
    await engine.start();
    const audioContext = engine.getContext();
    if (!audioContext) {
        setMidiStatus('Failed to initialize Audio Context.');
        return;
    }
    audioEngine.current = engine;

    drumMachineEngine.current = new DrumMachineEngine(audioContext, (step) => setCurrentStep(step));
    drumMachineEngine.current.setPattern(drumPattern);
    drumMachineEngine.current.setSwing(swing);
    Object.entries(drumPitches).forEach(([track, pitch]) => {
        drumMachineEngine.current?.setTrackPitch(track as DrumTrackName, pitch);
    });

    setIsStarted(true);
    setMidiStatus('Initializing MIDI...');

    try {
      const midiAccess = await navigator.requestMIDIAccess();
      setMidiStatus('MIDI Access Granted');

      if (midiAccess.inputs.size > 0) {
        const devices: string[] = [];
        midiAccess.inputs.forEach((input) => {
          devices.push(input.name || 'Unknown Device');
          input.onmidimessage = (e) => handleMidiMessage(e);
        });
        setMidiStatus(`Connected to: ${devices.join(', ')}`);
      } else {
        setMidiStatus('No MIDI input devices found.');
      }

      midiAccess.onstatechange = (event: Event) => {
          const port = (event as MIDIConnectionEvent).port;
          if (port.type === 'input') {
              const deviceName = port.name || 'Unknown Device';
              if (port.state === 'connected') {
                  setMidiStatus(`MIDI device connected: ${deviceName}`);
              } else {
                  setMidiStatus(`MIDI device disconnected: ${deviceName}`);
              }
          }
      };

    } catch (error) {
      console.error('MIDI Access Denied:', error);
      setMidiStatus('MIDI access denied by user.');
    }
  }, [isStarted]);

  useEffect(() => {
    if (audioEngine.current) {
      audioEngine.current.updateParams(params);
    }
  }, [params]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setBpm(bpm);
      }
  }, [bpm]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setSwing(swing);
      }
  }, [swing]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setPattern(drumPattern);
      }
  }, [drumPattern]);

  const handleDrumPitchChange = (val: number) => {
      const newPitches = { ...drumPitches, [selectedTrack]: val };
      setDrumPitches(newPitches);
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setTrackPitch(selectedTrack, val);
      }
  };

  const handleStepToggle = (track: DrumTrackName, stepIndex: number) => {
    const newBanks = [...banks];
    const currentPattern = { ...newBanks[currentBankIndex] };
    const newTrackPattern = [...currentPattern[track]];

    const isOn = newTrackPattern[stepIndex] === 0;
    newTrackPattern[stepIndex] = isOn ? 1 : 0;

    currentPattern[track] = newTrackPattern;
    newBanks[currentBankIndex] = currentPattern;

    setBanks(newBanks);

    if (isOn && drumMachineEngine.current) {
      drumMachineEngine.current.playSound(track);
    }
  };


  const handleMidiMessage = (message: MIDIMessageEvent) => {
    if (!audioEngine.current) return;

    const [command, note, velocity] = message.data;
    if (command === 144 && velocity > 0) {
      audioEngine.current.noteOn(note, velocity);
      setActiveNotes(prev => new Set(prev).add(note));
    } else if (command === 128 || (command === 144 && velocity === 0)) {
      audioEngine.current.noteOff(note);
      setActiveNotes(prev => {
        const newSet = new Set(prev);
        newSet.delete(note);
        return newSet;
      });
    }
  };

  const handleNoteOn = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOn(note, 100);
    setActiveNotes(prev => new Set(prev).add(note));
  };

  const handleNoteOff = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOff(note);
    setActiveNotes(prev => {
      const newSet = new Set(prev);
      newSet.delete(note);
      return newSet;
    });
  };

  const setOscWaveform = (osc: 'osc1' | 'osc2', waveform: Waveform) => {
    setParams(p => ({ ...p, [osc]: { ...p[osc], waveform } }));
  };

  const handlePlayToggle = () => {
      if (!drumMachineEngine.current) return;
      const nextIsPlaying = !isDrumMachinePlaying;
      setIsDrumMachinePlaying(nextIsPlaying);
      if (nextIsPlaying) {
          drumMachineEngine.current.play();
      } else {
          drumMachineEngine.current.stop();
          setCurrentStep(null);
      }
  };

  const renderWaveformSelector = (osc: 'osc1' | 'osc2') => (
    <div className="flex items-center space-x-2 bg-[#111] p-1 rounded-sm border border-[#222]">
      {(['sine', 'triangle', 'sawtooth', 'square'] as Waveform[]).map(w => {
        const isActive = params[osc].waveform === w;
        const Icon = { sine: SineIcon, triangle: TriangleIcon, sawtooth: SawtoothIcon, square: SquareIcon }[w];
        return (
          <button 
            key={w} 
            onClick={() => setOscWaveform(osc, w)} 
            className={`p-2 rounded-sm transition-all duration-100 relative group
                ${isActive 
                    ? 'bg-[#333] text-white shadow-[0_0_5px_rgba(255,255,255,0.2)] border border-gray-600' 
                    : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                }`}
          >
            <Icon className="w-5 h-5"/>
            {/* LED Indicator */}
            {isActive && <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-1 h-1 bg-white rounded-full shadow-[0_0_4px_white]"></div>}
          </button>
        );
      })}
    </div>
  );

  if (!isStarted) {
    return (
        <div className="flex flex-col items-center justify-center bg-[#1a1a1a] border border-[#333] rounded-sm p-16 shadow-2xl">
            <h2 className="text-2xl font-bold text-white mb-2 tracking-wider">SYSTEM STANDBY</h2>
            <p className="text-gray-500 mb-8 font-mono text-xs">{midiStatus}</p>
            <button
                onClick={handleStart}
                className="px-8 py-3 bg-[#222] text-gray-200 border border-gray-600 font-bold text-sm tracking-widest rounded-sm hover:bg-gray-200 hover:text-black hover:border-white transition-all duration-200 shadow-lg"
            >
                INITIALIZE ENGINE
            </button>
        </div>
    );
  }

  return (
    <div className="space-y-8">

      {/* Top Section: Oscillators, Filter, Envelopes */}
      <div className="flex flex-col xl:flex-row gap-8 items-stretch">

        {/* Left: Oscillators */}
        <Panel title="VCO" className="flex-1 justify-center min-h-[300px]">
             <div className="flex flex-col gap-10 py-4 w-full max-w-2xl">
                <div className="flex flex-col md:flex-row items-center justify-around gap-12 border-b border-[#222] pb-8">
                    <div className="flex flex-col items-center gap-3">
                        <span className="text-gray-500 text-[10px] font-mono tracking-widest">OSCILLATOR 1</span>
                        {renderWaveformSelector('osc1')}
                    </div>
                     <div className="flex flex-col items-center gap-3">
                        <span className="text-gray-500 text-[10px] font-mono tracking-widest">OSCILLATOR 2</span>
                        {renderWaveformSelector('osc2')}
                    </div>
                </div>
                <div className="flex items-center justify-center gap-16 pt-2">
                   <Knob label="Mix" value={params.oscMix} min={0} max={1} onChange={v => setParams(p => ({ ...p, oscMix: v }))} />
                   <Knob label="Pitch" value={params.osc2.detune} min={-100} max={100} onChange={v => setParams(p => ({ ...p, osc2: { ...p.osc2, detune: v } }))} />
                </div>
            </div>
        </Panel>

        {/* Right: Filter & Envelopes Group */}
        <div className="flex flex-col sm:flex-row gap-8 shrink-0 xl:w-[500px]">

            {/* Filter */}
            <Panel title="VCF" className="sm:w-1/3 justify-between">
                <div className="flex flex-col gap-6 h-full justify-center py-2">
                    <Knob label="Cutoff" value={params.filter.cutoff} min={20} max={20000} onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, cutoff: v } }))} />
                    <Knob label="Resonance" value={params.filter.resonance} min={0} max={40} onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, resonance: v } }))} />
                    <Knob label="EG Int" value={params.filterEnvelope.amount} min={0} max={10000} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, amount: v } }))} />
                </div>
            </Panel>

            {/* Envelopes */}
            <div className="flex flex-col gap-8 sm:w-2/3">
                <Panel title="AMP EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        <Knob label="Attack" value={params.ampEnvelope.attack} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.ampEnvelope.decay} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.ampEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, sustain: v } }))} />
                        <Knob label="Release" value={params.ampEnvelope.release} min={0.001} max={5} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, release: v } }))} />
                    </div>
                </Panel>

                <Panel title="FILTER EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        <Knob label="Attack" value={params.filterEnvelope.attack} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.filterEnvelope.decay} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.filterEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, sustain: v } }))} />
                        <Knob label="Release" value={params.filterEnvelope.release} min={0.001} max={5} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, release: v } }))} />
                    </div>
                </Panel>
            </div>
        </div>

      </div>

      <DrumMachine
        isPlaying={isDrumMachinePlaying}
        onPlayToggle={handlePlayToggle}
        bpm={bpm}
        onBpmChange={setBpm}
        pattern={drumPattern}
        selectedTrack={selectedTrack}
        onTrackSelect={setSelectedTrack}
        onStepToggle={handleStepToggle}
        currentStep={currentStep}
        currentBank={currentBankIndex}
        onBankSelect={setCurrentBankIndex}
        swing={swing}
        onSwingChange={setSwing}
        trackPitch={drumPitches[selectedTrack]}
        onTrackPitchChange={handleDrumPitchChange}
       />

      <div className="bg-[#1a1a1a] rounded-sm border-t-4 border-[#111] shadow-2xl">
        <Keyboard onNoteOn={handleNoteOn} onNoteOff={handleNoteOff} activeNotes={activeNotes} />
        <div className="bg-[#0a0a0a] text-center text-[10px] text-gray-600 py-1 font-mono uppercase tracking-widest">{midiStatus}</div>
      </div>
    </div>
  );
};

import React from 'react';
import { Knob } from './Knob';
import { StepSequencePattern, DrumTrackName } from '../types';
import { DRUM_TRACKS } from '../constants';

interface DrumMachineProps {
  isPlaying: boolean;
  onPlayToggle: () => void;
  bpm: number;
  onBpmChange: (bpm: number) => void;
  pattern: StepSequencePattern;
  selectedTrack: DrumTrackName;
  onTrackSelect: (track: DrumTrackName) => void;
