export type Waveform = 'sine' | 'square' | 'sawtooth' | 'triangle';

export interface ADSR {
  attack: number;
  decay: number;
  sustain: number;
  release: number;
}

export interface OscillatorParams {
  waveform: Waveform;
  detune: number; // In cents
  enabled: boolean;
}

export interface SynthParameters {
  osc1: OscillatorParams;
  osc2: OscillatorParams;
  osc3: OscillatorParams;
  osc4: OscillatorParams;
  oscMix: number; // Used to balance Osc 1 and 2 (legacy behavior), Osc 3/4 have fixed mix
  filter: {
    cutoff: number;
    resonance: number;
  };
  ampEnvelope: ADSR;
  filterEnvelope: ADSR & {
    amount: number;
  };
}

