import { SynthParameters } from '../types';

interface ActiveNote {
  osc1: OscillatorNode;
  osc2: OscillatorNode;
  osc3: OscillatorNode;
  osc4: OscillatorNode;
  osc1Gain: GainNode;
  osc2Gain: GainNode;
  osc3Gain: GainNode;
  osc4Gain: GainNode;
  filter: BiquadFilterNode;
  amp: GainNode;
}

export class AudioEngine {
  private audioContext: AudioContext | null = null;
  private activeNotes = new Map<number, ActiveNote>();
  private params: SynthParameters;

  constructor(initialParams: SynthParameters) {
    this.params = initialParams;
  }

  public async start() {
    if (this.audioContext && this.audioContext.state === 'running') {
      return;
    }
    this.audioContext = new AudioContext();
    if (this.audioContext.state === 'suspended') {
      await this.audioContext.resume();
    }
  }

  public getContext(): AudioContext | null {
      return this.audioContext;
  }

  public updateParams(newParams: SynthParameters) {
    this.params = newParams;
    if (!this.audioContext) return;

    const now = this.audioContext.currentTime;
    // Update params for all currently playing notes
    for (const note of this.activeNotes.values()) {
        // Waveforms
        if (note.osc1.type !== this.params.osc1.waveform) note.osc1.type = this.params.osc1.waveform;
        if (note.osc2.type !== this.params.osc2.waveform) note.osc2.type = this.params.osc2.waveform;
        if (note.osc3.type !== this.params.osc3.waveform) note.osc3.type = this.params.osc3.waveform;
        if (note.osc4.type !== this.params.osc4.waveform) note.osc4.type = this.params.osc4.waveform;

        // Pitch
        // Note: We don't ramp pitch aggressively to avoid glides unless intended
        note.osc1.detune.setValueAtTime(this.params.osc1.detune, now);
        note.osc2.detune.setValueAtTime(this.params.osc2.detune, now);
        note.osc3.detune.setValueAtTime(this.params.osc3.detune, now);
        note.osc4.detune.setValueAtTime(this.params.osc4.detune, now);

        // Mix / Gain / Enabled State
        // We scale gains to keep overall output roughly consistent
        // Base mix for 1/2
        const osc1Base = (1 - this.params.oscMix) * 0.4;
        const osc2Base = this.params.oscMix * 0.4;
        const osc3Base = 0.3; // Fixed gain for extra oscs
        const osc4Base = 0.3;

        note.osc1Gain.gain.setTargetAtTime(this.params.osc1.enabled ? osc1Base : 0, now, 0.01);
        note.osc2Gain.gain.setTargetAtTime(this.params.osc2.enabled ? osc2Base : 0, now, 0.01);
        note.osc3Gain.gain.setTargetAtTime(this.params.osc3.enabled ? osc3Base : 0, now, 0.01);
        note.osc4Gain.gain.setTargetAtTime(this.params.osc4.enabled ? osc4Base : 0, now, 0.01);

        // Filter
        note.filter.Q.setTargetAtTime(this.params.filter.resonance, now, 0.01);
    }
  }

  private midiToFrequency(note: number): number {
    return 440 * Math.pow(2, (note - 69) / 12);
  }

  public noteOn(note: number, velocity: number = 127) {
    if (!this.audioContext) return;

    // If note is already playing, stop it before retriggering
    if (this.activeNotes.has(note)) {
      this.noteOff(note);
    }

    const now = this.audioContext.currentTime;
    const frequency = this.midiToFrequency(note);
    const velocityGain = velocity / 127;

    // Common Graph
    const filter = this.audioContext.createBiquadFilter();
    filter.type = 'lowpass';
    filter.Q.setValueAtTime(this.params.filter.resonance, now);

    const amp = this.audioContext.createGain();
    amp.gain.setValueAtTime(0, now);

    filter.connect(amp);
    amp.connect(this.audioContext.destination);

    // Create Oscillators
    const createOsc = (params: any, baseGain: number) => {
        const osc = this.audioContext!.createOscillator();
        osc.type = params.waveform;
        osc.frequency.setValueAtTime(frequency, now);
        osc.detune.setValueAtTime(params.detune, now);

        const gain = this.audioContext!.createGain();
        const targetGain = params.enabled ? baseGain : 0;
        gain.gain.setValueAtTime(targetGain, now);

        osc.connect(gain).connect(filter);
        osc.start(now);
        return { osc, gain };
    };

    const osc1Obj = createOsc(this.params.osc1, (1 - this.params.oscMix) * 0.4);
    const osc2Obj = createOsc(this.params.osc2, this.params.oscMix * 0.4);
    const osc3Obj = createOsc(this.params.osc3, 0.3);
    const osc4Obj = createOsc(this.params.osc4, 0.3);

    // Envelopes
    const { attack: ampAttack, decay: ampDecay, sustain: ampSustain } = this.params.ampEnvelope;
    const peakAmp = velocityGain;
    const sustainAmp = peakAmp * ampSustain;
    amp.gain.linearRampToValueAtTime(peakAmp, now + ampAttack);
    amp.gain.linearRampToValueAtTime(sustainAmp, now + ampAttack + ampDecay);

    const { attack: filterAttack, decay: filterDecay, sustain: filterSustain, amount: filterAmount } = this.params.filterEnvelope;
    const baseCutoff = this.params.filter.cutoff;
    const peakFreq = Math.min(22000, baseCutoff + filterAmount * velocityGain);
    const sustainFreq = Math.min(22000, baseCutoff + filterAmount * filterSustain * velocityGain);

    filter.frequency.setValueAtTime(baseCutoff, now);
    filter.frequency.linearRampToValueAtTime(peakFreq, now + filterAttack);
    filter.frequency.linearRampToValueAtTime(sustainFreq, now + filterAttack + filterDecay);

    this.activeNotes.set(note, { 
        osc1: osc1Obj.osc, osc1Gain: osc1Obj.gain,
        osc2: osc2Obj.osc, osc2Gain: osc2Obj.gain,
        osc3: osc3Obj.osc, osc3Gain: osc3Obj.gain,
        osc4: osc4Obj.osc, osc4Gain: osc4Obj.gain,
        filter, amp 
    });
  }

  public noteOff(note: number) {
    if (!this.audioContext || !this.activeNotes.has(note)) {
      return;
    }

    const { osc1, osc2, osc3, osc4, filter, amp } = this.activeNotes.get(note)!;
    // Remove note from active map immediately
    this.activeNotes.delete(note);

    const now = this.audioContext.currentTime;

    const { release: ampRelease } = this.params.ampEnvelope;
    amp.gain.cancelScheduledValues(now);
    amp.gain.setValueAtTime(amp.gain.value, now);
    amp.gain.linearRampToValueAtTime(0, now + ampRelease);

    const { release: filterRelease } = this.params.filterEnvelope;
    const baseCutoff = this.params.filter.cutoff;
    filter.frequency.cancelScheduledValues(now);
    filter.frequency.setValueAtTime(filter.frequency.value, now);
    filter.frequency.linearRampToValueAtTime(baseCutoff, now + filterRelease);

    const stopTime = now + Math.max(ampRelease, filterRelease);
    osc1.stop(stopTime);
    osc2.stop(stopTime);
    osc3.stop(stopTime);
    osc4.stop(stopTime);

    // Use osc1 onended for garbage collection trigger
    osc1.onended = () => {
      osc1.disconnect();
      osc2.disconnect();
      osc3.disconnect();
      osc4.disconnect();
      filter.disconnect();
      amp.disconnect();
    };
  }
}

