  attack: number;
  decay: number;
  sustain: number;
  release: number;
}

export interface OscillatorParams {
  waveform: Waveform;
  detune: number; // In cents
  enabled: boolean;
  gain: number; // 0 to 1
}

export interface SynthParameters {
  osc1: OscillatorParams;
  osc2: OscillatorParams;
  osc3: OscillatorParams;
  osc4: OscillatorParams;
  // oscMix removed in favor of individual gains
  filter: {
    cutoff: number;
    resonance: number;
  };
  ampEnvelope: ADSR;
  filterEnvelope: ADSR & {
    amount: number;
  };
}

