  waveform: Waveform;
  detune: number; // In cents
  enabled: boolean;
  gain: number; // 0 to 1
}

export type LFOTarget = 'pitch' | 'filter' | 'amp';

export interface LFOParams {
  waveform: Waveform;
  rate: number; // Hz
  depth: number; // 0 to 1
  target: LFOTarget;
}

