    <div className="absolute top-2 right-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-12"></div></div>
    <div className="absolute bottom-2 left-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-90"></div></div>
    <div className="absolute bottom-2 right-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-[-45deg]"></div></div>

    <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mb-6 border-b border-gray-700 pb-1 px-2">{title}</h3>
    {children}
  </div>
);

export const Synth: React.FC = () => {
  const [params, setParams] = useState<SynthParameters>(DEFAULT_SYNTH_PARAMS);
  const [midiStatus, setMidiStatus] = useState<string>('Not initialized. Click to start.');
  const [isStarted, setIsStarted] = useState(false);
  const [activeNotes, setActiveNotes] = useState<Set<number>>(new Set());

  // Drum Machine State
  const [banks, setBanks] = useState<StepSequencePattern[]>(() => 
    Array(4).fill(null).map(() => JSON.parse(JSON.stringify(DEFAULT_DRUM_PATTERN)))
  );
  const [currentBankIndex, setCurrentBankIndex] = useState<number>(0);
  const drumPattern = banks[currentBankIndex];

  const [selectedTrack, setSelectedTrack] = useState<DrumTrackName>('kick');
  const [isDrumMachinePlaying, setIsDrumMachinePlaying] = useState(false);
  const [bpm, setBpm] = useState(DEFAULT_BPM);
  const [swing, setSwing] = useState(0);
  const [drumPitches, setDrumPitches] = useState<Record<DrumTrackName, number>>({
      kick: 0,
      snare: 0,
      hihat: 0,
      crash: 0
  });
  const [currentStep, setCurrentStep] = useState<number | null>(null);

  const audioEngine = useRef<AudioEngine | null>(null);
  const drumMachineEngine = useRef<DrumMachineEngine | null>(null);

  const handleStart = useCallback(async () => {
    if (isStarted) return;

    const engine = new AudioEngine(DEFAULT_SYNTH_PARAMS);
    await engine.start();
    const audioContext = engine.getContext();
    if (!audioContext) {
        setMidiStatus('Failed to initialize Audio Context.');
        return;
    }
    audioEngine.current = engine;

    drumMachineEngine.current = new DrumMachineEngine(audioContext, (step) => setCurrentStep(step));
    drumMachineEngine.current.setPattern(drumPattern);
    drumMachineEngine.current.setSwing(swing);
    Object.entries(drumPitches).forEach(([track, pitch]) => {
        drumMachineEngine.current?.setTrackPitch(track as DrumTrackName, pitch);
    });

    setIsStarted(true);
    setMidiStatus('Initializing MIDI...');

    try {
      const midiAccess = await navigator.requestMIDIAccess();
      setMidiStatus('MIDI Access Granted');

      if (midiAccess.inputs.size > 0) {
        const devices: string[] = [];
        midiAccess.inputs.forEach((input) => {
          devices.push(input.name || 'Unknown Device');
          input.onmidimessage = (e) => handleMidiMessage(e);
        });
        setMidiStatus(`Connected to: ${devices.join(', ')}`);
      } else {
        setMidiStatus('No MIDI input devices found.');
      }

      midiAccess.onstatechange = (event: Event) => {
          const port = (event as MIDIConnectionEvent).port;
          if (port.type === 'input') {
              const deviceName = port.name || 'Unknown Device';
              if (port.state === 'connected') {
                  setMidiStatus(`MIDI device connected: ${deviceName}`);
              } else {
                  setMidiStatus(`MIDI device disconnected: ${deviceName}`);
              }
          }
      };

    } catch (error) {
      console.error('MIDI Access Denied:', error);
      setMidiStatus('MIDI access denied by user.');
    }
  }, [isStarted]);

  useEffect(() => {
    if (audioEngine.current) {
      audioEngine.current.updateParams(params);
    }
  }, [params]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setBpm(bpm);
      }
  }, [bpm]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setSwing(swing);
      }
  }, [swing]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setPattern(drumPattern);
      }
  }, [drumPattern]);

  const handleDrumPitchChange = (val: number) => {
      const newPitches = { ...drumPitches, [selectedTrack]: val };
      setDrumPitches(newPitches);
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setTrackPitch(selectedTrack, val);
      }
  };

  const handleStepToggle = (track: DrumTrackName, stepIndex: number) => {
    const newBanks = [...banks];
    const currentPattern = { ...newBanks[currentBankIndex] };
    const newTrackPattern = [...currentPattern[track]];

    const isOn = newTrackPattern[stepIndex] === 0;
    newTrackPattern[stepIndex] = isOn ? 1 : 0;

    currentPattern[track] = newTrackPattern;
    newBanks[currentBankIndex] = currentPattern;

    setBanks(newBanks);

    if (isOn && drumMachineEngine.current) {
      drumMachineEngine.current.playSound(track);
    }
  };


  const handleMidiMessage = (message: MIDIMessageEvent) => {
    if (!audioEngine.current) return;

    const [command, note, velocity] = message.data;
    if (command === 144 && velocity > 0) {
      audioEngine.current.noteOn(note, velocity);
      setActiveNotes(prev => new Set(prev).add(note));
    } else if (command === 128 || (command === 144 && velocity === 0)) {
      audioEngine.current.noteOff(note);
      setActiveNotes(prev => {
        const newSet = new Set(prev);
        newSet.delete(note);
        return newSet;
      });
    }
  };

  const handleNoteOn = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOn(note, 100);
    setActiveNotes(prev => new Set(prev).add(note));
  };

  const handleNoteOff = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOff(note);
    setActiveNotes(prev => {
      const newSet = new Set(prev);
      newSet.delete(note);
      return newSet;
    });
  };

  const setOscWaveform = (osc: 'osc1' | 'osc2' | 'osc3' | 'osc4', waveform: Waveform) => {
    setParams(p => ({ ...p, [osc]: { ...p[osc], waveform } }));
  };

  const toggleOsc = (osc: 'osc1' | 'osc2' | 'osc3' | 'osc4') => {
      setParams(p => ({...p, [osc]: {...p[osc], enabled: !p[osc].enabled } }));
  }

  const setLfoWaveform = (waveform: Waveform) => {
      setParams(p => ({ ...p, lfo: { ...p.lfo, waveform } }));
  };

  const handlePlayToggle = () => {
      if (!drumMachineEngine.current) return;
      const nextIsPlaying = !isDrumMachinePlaying;
      setIsDrumMachinePlaying(nextIsPlaying);
      if (nextIsPlaying) {
          drumMachineEngine.current.play();
      } else {
          drumMachineEngine.current.stop();
          setCurrentStep(null);
      }
  };

  const renderOscControl = (oscKey: 'osc1' | 'osc2' | 'osc3' | 'osc4', label: string) => {
      const oscParams = params[oscKey];
      return (
        <div className="flex flex-col gap-2 border border-[#222] p-2 rounded-sm bg-[#111] w-full relative">
            <div className="flex items-center gap-2 mb-1 w-full justify-between px-1 border-b border-[#222] pb-1">
                <span className="text-gray-500 text-[10px] font-mono tracking-widest">{label}</span>
                {/* Red Light Toggle */}
                <button 
                    onClick={() => toggleOsc(oscKey)}
                    className={`w-3 h-3 rounded-full transition-all duration-300 border border-red-900 ${oscParams.enabled ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,1)]' : 'bg-[#300] shadow-inner'}`}
                    aria-label={`Toggle ${label}`}
                />
            </div>

            <div className="flex flex-row items-stretch w-full gap-4 px-1">
                 {/* Vertical Waveform Icons */}
                <div className="flex flex-col gap-1 bg-[#0a0a0a] p-1 rounded-sm border border-[#222] h-full justify-between w-8 shrink-0">
                    {(['sine', 'triangle', 'sawtooth', 'square'] as Waveform[]).map(w => {
                        const isActive = oscParams.waveform === w;
                        const Icon = { sine: SineIcon, triangle: TriangleIcon, sawtooth: SawtoothIcon, square: SquareIcon }[w];
                        return (
                        <button 
                            key={w} 
                            onClick={() => setOscWaveform(oscKey, w)} 
                            className={`p-1 rounded-sm transition-all duration-100 flex items-center justify-center h-6
                                ${isActive 
                                    ? 'bg-[#333] text-white shadow-[0_0_5px_rgba(255,255,255,0.2)] border border-gray-600' 
                                    : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                                }`}
                        >
                            <Icon className="w-4 h-4"/>
                        </button>
                        );
                    })}
                </div>

                {/* Middle Section: LCD Display, Visualizer, Volume */}
                <div className="flex flex-col flex-1 justify-between gap-1 min-w-[80px]">
                    {/* LCD Display - Smaller height */}
                    <div className="bg-[#081008] border border-[#222] rounded-sm px-1 py-0.5 shadow-inner flex items-center justify-center h-5 w-full overflow-hidden">
                        <span className="font-mono text-[#44ff44] text-[9px] tracking-widest uppercase opacity-80">
                            {oscParams.waveform}
                        </span>
                    </div>

                    {/* Visualizer */}
                    <div className="flex-1 w-full min-h-[36px] my-0.5">
                        <WaveformDisplay waveform={oscParams.waveform} isPlaying={oscParams.enabled} />
                    </div>

                    {/* Volume Slider */}
                     <div className="flex flex-col w-full px-1">
                        <div className="flex justify-between items-end mb-1">
                             <label className="text-[8px] text-gray-500 uppercase font-mono leading-none">Vol</label>
                             <span className="text-[8px] text-gray-400 font-mono leading-none">{Math.round(oscParams.gain * 100)}</span>
                        </div>
                        <input
                            type="range"
                            min="0"
                            max="1"
                            step="0.01"
                            value={oscParams.gain}
                            onChange={(e) => setParams(p => ({ ...p, [oscKey]: { ...p[oscKey], gain: parseFloat(e.target.value) } }))}
                            className="w-full h-1.5 bg-[#222] rounded-lg appearance-none cursor-pointer accent-white"
                        />
                    </div>
                </div>

                {/* Right Section: Pitch Knob */}
                 <div className="flex items-center justify-center border-l border-[#222] pl-3">
                    <Knob 
                        label="Pitch" 
                        value={oscParams.detune} 
                        min={-2400} 
                        max={2400} 
                        size={32}
                        onChange={v => setParams(p => ({ ...p, [oscKey]: { ...p[oscKey], detune: v } }))} 
                    />
                 </div>
            </div>
        </div>
      );
  };

  if (!isStarted) {
    return (
        <div className="flex flex-col items-center justify-center bg-[#1a1a1a] border border-[#333] rounded-sm p-16 shadow-2xl">
            <h2 className="text-2xl font-bold text-white mb-2 tracking-wider">SYSTEM STANDBY</h2>
            <p className="text-gray-500 mb-8 font-mono text-xs">{midiStatus}</p>
            <button
                onClick={handleStart}
                className="px-8 py-3 bg-[#222] text-gray-200 border border-gray-600 font-bold text-sm tracking-widest rounded-sm hover:bg-gray-200 hover:text-black hover:border-white transition-all duration-200 shadow-lg"
            >
                INITIALIZE ENGINE
            </button>
        </div>
    );
  }

  return (
    <div className="space-y-8">

      {/* Top Section: Oscillators, Filter, Envelopes */}
      <div className="flex flex-col xl:flex-row gap-8 items-stretch">

        {/* Left: Oscillators */}
        <Panel title="VCO" className="flex-1 justify-center">
             <div className="flex flex-col gap-6 py-2 w-full max-w-2xl">
                {/* 2x2 Grid for Oscillators */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pb-2">
                    {renderOscControl('osc1', 'OSC 1')}
                    {renderOscControl('osc2', 'OSC 2')}
                    {renderOscControl('osc3', 'OSC 3')}
                    {renderOscControl('osc4', 'OSC 4')}
                </div>
            </div>
        </Panel>

        {/* Right: Filter & Envelopes Group & LFO */}
        <div className="flex flex-col sm:flex-row gap-8 shrink-0 xl:w-[500px]">

            <div className="flex flex-col gap-8 sm:w-1/3">
                 {/* Filter */}
                <Panel title="VCF" className="flex-1 justify-between">
                    <div className="flex flex-col gap-6 h-full justify-center py-2">
                        {/* Logarithmic Cutoff for better feel */}
                        <Knob label="Cutoff" value={params.filter.cutoff} min={20} max={20000} logarithmic onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, cutoff: v } }))} />
                        <Knob label="Resonance" value={params.filter.resonance} min={0} max={40} onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, resonance: v } }))} />
                        {/* Increased EG Int max for stronger modulation effect */}
                        <Knob label="EG Int" value={params.filterEnvelope.amount} min={0} max={20000} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, amount: v } }))} />
                    </div>
                </Panel>
            </div>


            {/* Envelopes & LFO */}
            <div className="flex flex-col gap-8 sm:w-2/3">
                <Panel title="LFO" className="justify-center">
                    <div className="flex flex-col gap-3">
                         <div className="flex flex-row items-center w-full gap-4">
                            {/* LFO Waveform */}
                             <div className="flex flex-col gap-1 bg-[#0a0a0a] p-1 rounded-sm border border-[#222]">
                                {(['sine', 'triangle', 'sawtooth', 'square'] as Waveform[]).map(w => {
                                    const isActive = params.lfo.waveform === w;
                                    const Icon = { sine: SineIcon, triangle: TriangleIcon, sawtooth: SawtoothIcon, square: SquareIcon }[w];
                                    return (
                                    <button 
                                        key={w} 
                                        onClick={() => setLfoWaveform(w)} 
                                        className={`p-1.5 rounded-sm transition-all duration-100 flex items-center justify-center
                                            ${isActive 
                                                ? 'bg-[#333] text-white shadow-[0_0_5px_rgba(255,255,255,0.2)] border border-gray-600' 
                                                : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                                            }`}
                                    >
                                        <Icon className="w-3 h-3"/>
                                    </button>
                                    );
                                })}
                            </div>

                            {/* Controls */}
                            <div className="flex flex-wrap gap-2">
                                 <Knob label="Rate" value={params.lfo.rate} min={0.1} max={20} size={40} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, rate: v } }))} />
                                 <Knob label="Depth" value={params.lfo.depth} min={0} max={1} size={40} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, depth: v } }))} />
                                 <Knob label="Delay" value={params.lfo.delay} min={0} max={2} size={40} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, delay: v } }))} />
                                 <Knob label="Fade" value={params.lfo.fade} min={0} max={2} size={40} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, fade: v } }))} />
                            </div>
                         </div>

                        {/* Target Selector */}
                        <div className="flex items-center gap-2 text-[9px] font-mono uppercase tracking-wide border-t border-[#333] pt-2 w-full">
                            <span className="text-gray-500 mr-2">Target:</span>
                            {(['pitch', 'filter', 'amp'] as LFOTarget[]).map(target => (
                                <button
                                    key={target}
                                    onClick={() => setParams(p => ({ ...p, lfo: { ...p.lfo, target: target } }))}
                                    className={`px-2 py-0.5 rounded-sm transition-colors ${
                                        params.lfo.target === target 
                                        ? 'bg-[#333] text-white' 
                                        : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                                    }`}
                                >
                                    {target}
                                </button>
                            ))}
                        </div>
                    </div>
                </Panel>

                <Panel title="AMP EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        <Knob label="Attack" value={params.ampEnvelope.attack} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.ampEnvelope.decay} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.ampEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, sustain: v } }))} />
                        <Knob label="Release" value={params.ampEnvelope.release} min={0.001} max={5} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, release: v } }))} />
                    </div>
                </Panel>

                <Panel title="FILTER EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        {/* Finer control for Attack and Decay (max 1s) */}
                        <Knob label="Attack" value={params.filterEnvelope.attack} min={0.001} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.filterEnvelope.decay} min={0.001} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.filterEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, sustain: v } }))} />
                        {/* Extended Release range (max 10s) */}
                        <Knob label="Release" value={params.filterEnvelope.release} min={0.001} max={10} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, release: v } }))} />
                    </div>
                </Panel>
            </div>
        </div>

      </div>

      <DrumMachine
        isPlaying={isDrumMachinePlaying}
        onPlayToggle={handlePlayToggle}
        bpm={bpm}
        onBpmChange={setBpm}
        pattern={drumPattern}
        selectedTrack={selectedTrack}
        onTrackSelect={setSelectedTrack}
        onStepToggle={handleStepToggle}
        currentStep={currentStep}
        currentBank={currentBankIndex}
        onBankSelect={setCurrentBankIndex}
        swing={swing}
        onSwingChange={setSwing}
        trackPitch={drumPitches[selectedTrack]}
        onTrackPitchChange={handleDrumPitchChange}
       />

      <div className="bg-[#1a1a1a] rounded-sm border-t-4 border-[#111] shadow-2xl">
        <Keyboard onNoteOn={handleNoteOn} onNoteOff={handleNoteOff} activeNotes={activeNotes} />
        <div className="bg-[#0a0a0a] text-center text-[10px] text-gray-600 py-1 font-mono uppercase tracking-widest">{midiStatus}</div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { Waveform } from '../types';

interface WaveformDisplayProps {
  waveform: Waveform;
  isPlaying?: boolean;
  color?: string;
  amplitudeScale?: number;
}

export const WaveformDisplay: React.FC<WaveformDisplayProps> = ({ waveform, isPlaying = true, color = '#4ade80', amplitudeScale = 1 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>(0);
  const phaseRef = useRef<number>(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Set internal resolution
    const dpr = window.devicePixelRatio || 1;
    // We'll use a fixed coordinate system for drawing logic, but scale for DPI
    // Getting actual size from DOM
    const rect = canvas.getBoundingClientRect();
    if (rect.width === 0 || rect.height === 0) return;

    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;

    const draw = () => {
      if (!ctx || !canvas) return;

      const width = canvas.width;
      const height = canvas.height;
      const centerY = height / 2;
      const amplitude = height * 0.35 * amplitudeScale;

      ctx.clearRect(0, 0, width, height);

      // CRT/Screen Background
      ctx.fillStyle = '#050505';
      ctx.fillRect(0, 0, width, height);

      // Grid
      ctx.beginPath();
      ctx.strokeStyle = '#112211';
      ctx.lineWidth = 1 * dpr;
      // Horizontal line
      ctx.moveTo(0, centerY);
      ctx.lineTo(width, centerY);
      ctx.stroke();

      // Waveform
      ctx.beginPath();
      ctx.strokeStyle = isPlaying ? color : '#1a441a'; // Dim if disabled
      ctx.lineWidth = 2 * dpr;
      ctx.lineJoin = 'round';
      ctx.lineCap = 'round';

      // 2 cycles across the width
      const cycles = 2;
      const frequency = (Math.PI * 2 * cycles) / width;

      for (let x = 0; x < width; x++) {
        // Moving phase
        const t = x * frequency - phaseRef.current;
        let y = 0;

        // Helper for 0..1 saw/tri
        const twoPi = 2 * Math.PI;
        // Normalize t to 0..1 for one cycle
        // ((t % 2PI) + 2PI) % 2PI gives 0..2PI. Divide by 2PI gives 0..1
        const normT = ((t % twoPi) + twoPi) % twoPi / twoPi; 

        switch (waveform) {
          case 'sine':
            y = Math.sin(t);
            break;
          case 'square':
            y = Math.sin(t) >= 0 ? 1 : -1;
            break;
          case 'sawtooth':
            // 1 -> -1
            y = 1 - 2 * normT;
            break;
          case 'triangle':
            // Triangle: 1 -> -1 -> 1
            // Standard: 2/PI * asin(sin(t)) maps to triangle wave [-1, 1]
            y = (2 / Math.PI) * Math.asin(Math.sin(t));
            break;
        }

        const yPos = centerY + y * amplitude;
        if (x === 0) ctx.moveTo(x, yPos);
        else ctx.lineTo(x, yPos);
      }
      ctx.stroke();

      // Glow (only if playing)
      if (isPlaying) {
          ctx.shadowBlur = 4 * dpr;
          ctx.shadowColor = color;
          ctx.stroke();
          ctx.shadowBlur = 0;

          phaseRef.current += 0.1;
          animationRef.current = requestAnimationFrame(draw);
      } else {
           // Static draw if not playing (no phase update)
           ctx.shadowBlur = 0;
           ctx.stroke();
      }
    };

    draw();

    return () => {
      cancelAnimationFrame(animationRef.current);
    };
  }, [waveform, isPlaying, color, amplitudeScale]);

  return <canvas ref={canvasRef} className="w-full h-full rounded-sm border border-[#222]" />;
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SynthParameters, Waveform, StepSequencePattern, DrumTrackName, LFOTarget } from '../types';
import { AudioEngine } from '../services/AudioEngine';
import { DrumMachineEngine } from '../services/DrumMachineEngine';
import { Knob } from './Knob';
import { Keyboard } from './Keyboard';
import { DrumMachine } from './DrumMachine';
import { DEFAULT_SYNTH_PARAMS, DEFAULT_BPM, DEFAULT_DRUM_PATTERN } from '../constants';
import { SineIcon, SawtoothIcon, SquareIcon, TriangleIcon } from './Icon';
import { WaveformDisplay } from './WaveformDisplay';

interface PanelProps {
  title: string;
  children: React.ReactNode;
  className?: string;
}

const Panel: React.FC<PanelProps> = ({ title, children, className = "" }) => (
  <div className={`relative bg-[#1a1a1a] rounded-sm border border-[#333] p-6 flex flex-col items-center shadow-xl ${className}`}>
    {/* Hardware Screw aesthetic */}
    <div className="absolute top-2 left-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-45"></div></div>
    <div className="absolute top-2 right-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-12"></div></div>
    <div className="absolute bottom-2 left-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-90"></div></div>
    <div className="absolute bottom-2 right-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-[-45deg]"></div></div>

    <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mb-6 border-b border-gray-700 pb-1 px-2">{title}</h3>
    {children}
  </div>
);

export const Synth: React.FC = () => {
  const [params, setParams] = useState<SynthParameters>(DEFAULT_SYNTH_PARAMS);
  const [midiStatus, setMidiStatus] = useState<string>('Not initialized. Click to start.');
  const [isStarted, setIsStarted] = useState(false);
  const [activeNotes, setActiveNotes] = useState<Set<number>>(new Set());

  // Drum Machine State
  const [banks, setBanks] = useState<StepSequencePattern[]>(() => 
    Array(4).fill(null).map(() => JSON.parse(JSON.stringify(DEFAULT_DRUM_PATTERN)))
  );
  const [currentBankIndex, setCurrentBankIndex] = useState<number>(0);
  const drumPattern = banks[currentBankIndex];

  const [selectedTrack, setSelectedTrack] = useState<DrumTrackName>('kick');
  const [isDrumMachinePlaying, setIsDrumMachinePlaying] = useState(false);
  const [bpm, setBpm] = useState(DEFAULT_BPM);
  const [swing, setSwing] = useState(0);
  const [drumPitches, setDrumPitches] = useState<Record<DrumTrackName, number>>({
      kick: 0,
      snare: 0,
      hihat: 0,
      crash: 0
  });
  const [currentStep, setCurrentStep] = useState<number | null>(null);

  const audioEngine = useRef<AudioEngine | null>(null);
  const drumMachineEngine = useRef<DrumMachineEngine | null>(null);

  const handleStart = useCallback(async () => {
    if (isStarted) return;

    const engine = new AudioEngine(DEFAULT_SYNTH_PARAMS);
    await engine.start();
    const audioContext = engine.getContext();
    if (!audioContext) {
        setMidiStatus('Failed to initialize Audio Context.');
        return;
    }
    audioEngine.current = engine;

    drumMachineEngine.current = new DrumMachineEngine(audioContext, (step) => setCurrentStep(step));
    drumMachineEngine.current.setPattern(drumPattern);
    drumMachineEngine.current.setSwing(swing);
    Object.entries(drumPitches).forEach(([track, pitch]) => {
        drumMachineEngine.current?.setTrackPitch(track as DrumTrackName, pitch);
    });

    setIsStarted(true);
    setMidiStatus('Initializing MIDI...');

    try {
      const midiAccess = await navigator.requestMIDIAccess();
      setMidiStatus('MIDI Access Granted');

      if (midiAccess.inputs.size > 0) {
        const devices: string[] = [];
        midiAccess.inputs.forEach((input) => {
          devices.push(input.name || 'Unknown Device');
          input.onmidimessage = (e) => handleMidiMessage(e);
        });
        setMidiStatus(`Connected to: ${devices.join(', ')}`);
      } else {
        setMidiStatus('No MIDI input devices found.');
      }

      midiAccess.onstatechange = (event: Event) => {
          const port = (event as MIDIConnectionEvent).port;
          if (port.type === 'input') {
              const deviceName = port.name || 'Unknown Device';
              if (port.state === 'connected') {
                  setMidiStatus(`MIDI device connected: ${deviceName}`);
              } else {
                  setMidiStatus(`MIDI device disconnected: ${deviceName}`);
              }
          }
      };

    } catch (error) {
      console.error('MIDI Access Denied:', error);
      setMidiStatus('MIDI access denied by user.');
    }
  }, [isStarted]);

  useEffect(() => {
    if (audioEngine.current) {
      audioEngine.current.updateParams(params);
    }
  }, [params]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setBpm(bpm);
      }
  }, [bpm]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setSwing(swing);
      }
  }, [swing]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setPattern(drumPattern);
      }
  }, [drumPattern]);

  const handleDrumPitchChange = (val: number) => {
      const newPitches = { ...drumPitches, [selectedTrack]: val };
      setDrumPitches(newPitches);
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setTrackPitch(selectedTrack, val);
      }
  };

  const handleStepToggle = (track: DrumTrackName, stepIndex: number) => {
    const newBanks = [...banks];
    const currentPattern = { ...newBanks[currentBankIndex] };
    const newTrackPattern = [...currentPattern[track]];

    const isOn = newTrackPattern[stepIndex] === 0;
    newTrackPattern[stepIndex] = isOn ? 1 : 0;

    currentPattern[track] = newTrackPattern;
    newBanks[currentBankIndex] = currentPattern;

    setBanks(newBanks);

    if (isOn && drumMachineEngine.current) {
      drumMachineEngine.current.playSound(track);
    }
  };


  const handleMidiMessage = (message: MIDIMessageEvent) => {
    if (!audioEngine.current) return;

    const [command, note, velocity] = message.data;
    if (command === 144 && velocity > 0) {
      audioEngine.current.noteOn(note, velocity);
      setActiveNotes(prev => new Set(prev).add(note));
    } else if (command === 128 || (command === 144 && velocity === 0)) {
      audioEngine.current.noteOff(note);
      setActiveNotes(prev => {
        const newSet = new Set(prev);
        newSet.delete(note);
        return newSet;
      });
    }
  };

  const handleNoteOn = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOn(note, 100);
    setActiveNotes(prev => new Set(prev).add(note));
  };

  const handleNoteOff = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOff(note);
    setActiveNotes(prev => {
      const newSet = new Set(prev);
      newSet.delete(note);
      return newSet;
    });
  };

  const setOscWaveform = (osc: 'osc1' | 'osc2' | 'osc3' | 'osc4', waveform: Waveform) => {
    setParams(p => ({ ...p, [osc]: { ...p[osc], waveform } }));
  };

  const toggleOsc = (osc: 'osc1' | 'osc2' | 'osc3' | 'osc4') => {
      setParams(p => ({...p, [osc]: {...p[osc], enabled: !p[osc].enabled } }));
  }

  const setLfoWaveform = (waveform: Waveform) => {
      setParams(p => ({ ...p, lfo: { ...p.lfo, waveform } }));
  };

  const handlePlayToggle = () => {
      if (!drumMachineEngine.current) return;
      const nextIsPlaying = !isDrumMachinePlaying;
      setIsDrumMachinePlaying(nextIsPlaying);
      if (nextIsPlaying) {
          drumMachineEngine.current.play();
      } else {
          drumMachineEngine.current.stop();
          setCurrentStep(null);
      }
  };

  const renderOscControl = (oscKey: 'osc1' | 'osc2' | 'osc3' | 'osc4', label: string) => {
      const oscParams = params[oscKey];
      return (
        <div className="flex flex-col gap-2 border border-[#222] p-2 rounded-sm bg-[#111] w-full relative">
            <div className="flex items-center gap-2 mb-1 w-full justify-between px-1 border-b border-[#222] pb-1">
                <span className="text-gray-500 text-[10px] font-mono tracking-widest">{label}</span>
                {/* Red Light Toggle */}
                <button 
                    onClick={() => toggleOsc(oscKey)}
                    className={`w-3 h-3 rounded-full transition-all duration-300 border border-red-900 ${oscParams.enabled ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,1)]' : 'bg-[#300] shadow-inner'}`}
                    aria-label={`Toggle ${label}`}
                />
            </div>

            <div className="flex flex-row items-stretch w-full gap-4 px-1">
                 {/* Vertical Waveform Icons */}
                <div className="flex flex-col gap-1 bg-[#0a0a0a] p-1 rounded-sm border border-[#222] h-full justify-between w-8 shrink-0">
                    {(['sine', 'triangle', 'sawtooth', 'square'] as Waveform[]).map(w => {
                        const isActive = oscParams.waveform === w;
                        const Icon = { sine: SineIcon, triangle: TriangleIcon, sawtooth: SawtoothIcon, square: SquareIcon }[w];
                        return (
                        <button 
                            key={w} 
                            onClick={() => setOscWaveform(oscKey, w)} 
                            className={`p-1 rounded-sm transition-all duration-100 flex items-center justify-center h-6
                                ${isActive 
                                    ? 'bg-[#333] text-white shadow-[0_0_5px_rgba(255,255,255,0.2)] border border-gray-600' 
                                    : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                                }`}
                        >
                            <Icon className="w-4 h-4"/>
                        </button>
                        );
                    })}
                </div>

                {/* Middle Section: LCD Display, Visualizer, Volume */}
                <div className="flex flex-col flex-1 justify-between gap-1 min-w-[80px]">
                    {/* LCD Display - Smaller height */}
                    <div className="bg-[#081008] border border-[#222] rounded-sm px-1 py-0.5 shadow-inner flex items-center justify-center h-5 w-full overflow-hidden">
                        <span className="font-mono text-[#44ff44] text-[9px] tracking-widest uppercase opacity-80">
                            {oscParams.waveform}
                        </span>
                    </div>

                    {/* Visualizer */}
                    <div className="flex-1 w-full min-h-[36px] my-0.5">
                        <WaveformDisplay 
                          waveform={oscParams.waveform} 
                          isPlaying={oscParams.enabled} 
                          amplitudeScale={oscParams.gain}
                        />
                    </div>

                    {/* Volume Slider */}
                     <div className="flex flex-col w-full px-1">
                        <div className="flex justify-between items-end mb-1">
                             <label className="text-[8px] text-gray-500 uppercase font-mono leading-none">Vol</label>
                             <span className="text-[8px] text-gray-400 font-mono leading-none">{Math.round(oscParams.gain * 100)}</span>
                        </div>
                        <input
                            type="range"
                            min="0"
                            max="1"
                            step="0.01"
                            value={oscParams.gain}
                            onChange={(e) => setParams(p => ({ ...p, [oscKey]: { ...p[oscKey], gain: parseFloat(e.target.value) } }))}
                            className="w-full h-1.5 bg-[#222] rounded-lg appearance-none cursor-pointer accent-white"
                        />
                    </div>
                </div>

                {/* Right Section: Pitch Knob */}
                 <div className="flex items-center justify-center border-l border-[#222] pl-3">
                    <Knob 
                        label="Pitch" 
                        value={oscParams.detune} 
                        min={-2400} 
                        max={2400} 
                        size={32}
                        onChange={v => setParams(p => ({ ...p, [oscKey]: { ...p[oscKey], detune: v } }))} 
                    />
                 </div>
            </div>
        </div>
      );
  };

  if (!isStarted) {
    return (
        <div className="flex flex-col items-center justify-center bg-[#1a1a1a] border border-[#333] rounded-sm p-16 shadow-2xl">
            <h2 className="text-2xl font-bold text-white mb-2 tracking-wider">SYSTEM STANDBY</h2>
            <p className="text-gray-500 mb-8 font-mono text-xs">{midiStatus}</p>
            <button
                onClick={handleStart}
                className="px-8 py-3 bg-[#222] text-gray-200 border border-gray-600 font-bold text-sm tracking-widest rounded-sm hover:bg-gray-200 hover:text-black hover:border-white transition-all duration-200 shadow-lg"
            >
                INITIALIZE ENGINE
            </button>
        </div>
    );
  }

  return (
    <div className="space-y-8">

      {/* Top Section: Oscillators, Filter, Envelopes */}
      <div className="flex flex-col xl:flex-row gap-8 items-stretch">

        {/* Left: Oscillators */}
        <Panel title="VCO" className="flex-1 justify-center">
             <div className="flex flex-col gap-6 py-2 w-full max-w-2xl">
                {/* 2x2 Grid for Oscillators */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pb-2">
                    {renderOscControl('osc1', 'OSC 1')}
                    {renderOscControl('osc2', 'OSC 2')}
                    {renderOscControl('osc3', 'OSC 3')}
                    {renderOscControl('osc4', 'OSC 4')}
                </div>
            </div>
        </Panel>

        {/* Right: Filter & Envelopes Group & LFO */}
        <div className="flex flex-col sm:flex-row gap-8 shrink-0 xl:w-[500px]">

            <div className="flex flex-col gap-8 sm:w-1/3">
                 {/* Filter */}
                <Panel title="VCF" className="flex-1 justify-between">
                    <div className="flex flex-col gap-6 h-full justify-center py-2">
                        {/* Logarithmic Cutoff for better feel */}
                        <Knob label="Cutoff" value={params.filter.cutoff} min={20} max={20000} logarithmic onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, cutoff: v } }))} />
                        <Knob label="Resonance" value={params.filter.resonance} min={0} max={40} onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, resonance: v } }))} />
                        {/* Increased EG Int max for stronger modulation effect */}
                        <Knob label="EG Int" value={params.filterEnvelope.amount} min={0} max={20000} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, amount: v } }))} />
                    </div>
                </Panel>
            </div>


            {/* Envelopes & LFO */}
            <div className="flex flex-col gap-8 sm:w-2/3">
                <Panel title="LFO" className="justify-center">
                    <div className="flex flex-col gap-3 w-full">
                         <div className="flex flex-row items-stretch w-full gap-4">
                            {/* LFO Waveform Buttons */}
                             <div className="flex flex-col gap-1 bg-[#0a0a0a] p-1 rounded-sm border border-[#222] justify-between">
                                {(['sine', 'triangle', 'sawtooth', 'square'] as Waveform[]).map(w => {
                                    const isActive = params.lfo.waveform === w;
                                    const Icon = { sine: SineIcon, triangle: TriangleIcon, sawtooth: SawtoothIcon, square: SquareIcon }[w];
                                    return (
                                    <button 
                                        key={w} 
                                        onClick={() => setLfoWaveform(w)} 
                                        className={`p-1.5 rounded-sm transition-all duration-100 flex items-center justify-center flex-1
                                            ${isActive 
                                                ? 'bg-[#333] text-white shadow-[0_0_5px_rgba(255,255,255,0.2)] border border-gray-600' 
                                                : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                                            }`}
                                    >
                                        <Icon className="w-3 h-3"/>
                                    </button>
                                    );
                                })}
                            </div>

                            {/* Middle: LFO Visualizer */}
                            <div className="flex flex-col flex-1 justify-between gap-1 min-w-[60px]">
                                {/* LCD */}
                                <div className="bg-[#081008] border border-[#222] rounded-sm px-1 py-0.5 shadow-inner flex items-center justify-center h-5 w-full overflow-hidden">
                                    <span className="font-mono text-[#4488ff] text-[9px] tracking-widest uppercase opacity-80">
                                        {params.lfo.waveform}
                                    </span>
                                </div>
                                {/* Visualizer */}
                                <div className="flex-1 w-full min-h-[40px] my-0.5">
                                    <WaveformDisplay 
                                        waveform={params.lfo.waveform} 
                                        isPlaying={activeNotes.size > 0}
                                        amplitudeScale={params.lfo.depth}
                                        color="#3b82f6" // Blue
                                    />
                                </div>
                            </div>

                            {/* Controls - Grid for compactness */}
                            <div className="grid grid-cols-2 gap-2">
                                 <Knob label="Rate" value={params.lfo.rate} min={0.1} max={20} size={36} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, rate: v } }))} />
                                 <Knob label="Depth" value={params.lfo.depth} min={0} max={1} size={36} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, depth: v } }))} />
                                 <Knob label="Delay" value={params.lfo.delay} min={0} max={2} size={36} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, delay: v } }))} />
                                 <Knob label="Fade" value={params.lfo.fade} min={0} max={2} size={36} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, fade: v } }))} />
                            </div>
                         </div>

                        {/* Target Selector */}
                        <div className="flex items-center gap-2 text-[9px] font-mono uppercase tracking-wide border-t border-[#333] pt-2 w-full justify-center">
                            <span className="text-gray-500 mr-2">Target:</span>
                            {(['pitch', 'filter', 'amp'] as LFOTarget[]).map(target => (
                                <button
                                    key={target}
                                    onClick={() => setParams(p => ({ ...p, lfo: { ...p.lfo, target: target } }))}
                                    className={`px-2 py-0.5 rounded-sm transition-colors ${
                                        params.lfo.target === target 
                                        ? 'bg-[#333] text-white' 
                                        : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                                    }`}
                                >
                                    {target}
                                </button>
                            ))}
                        </div>
                    </div>
                </Panel>

                <Panel title="AMP EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        <Knob label="Attack" value={params.ampEnvelope.attack} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.ampEnvelope.decay} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.ampEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, sustain: v } }))} />
                        <Knob label="Release" value={params.ampEnvelope.release} min={0.001} max={5} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, release: v } }))} />
                    </div>
                </Panel>

                <Panel title="FILTER EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        {/* Finer control for Attack and Decay (max 1s) */}
                        <Knob label="Attack" value={params.filterEnvelope.attack} min={0.001} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.filterEnvelope.decay} min={0.001} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.filterEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, sustain: v } }))} />
                        {/* Extended Release range (max 10s) */}
                        <Knob label="Release" value={params.filterEnvelope.release} min={0.001} max={10} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, release: v } }))} />
                    </div>
                </Panel>
            </div>
        </div>

      </div>

      <DrumMachine
        isPlaying={isDrumMachinePlaying}
        onPlayToggle={handlePlayToggle}
        bpm={bpm}
        onBpmChange={setBpm}
        pattern={drumPattern}
        selectedTrack={selectedTrack}
        onTrackSelect={setSelectedTrack}
        onStepToggle={handleStepToggle}
        currentStep={currentStep}
        currentBank={currentBankIndex}
        onBankSelect={setCurrentBankIndex}
        swing={swing}
        onSwingChange={setSwing}
        trackPitch={drumPitches[selectedTrack]}
        onTrackPitchChange={handleDrumPitchChange}
       />

      <div className="bg-[#1a1a1a] rounded-sm border-t-4 border-[#111] shadow-2xl">
        <Keyboard onNoteOn={handleNoteOn} onNoteOff={handleNoteOff} activeNotes={activeNotes} />
        <div className="bg-[#0a0a0a] text-center text-[10px] text-gray-600 py-1 font-mono uppercase tracking-widest">{midiStatus}</div>
      </div>
    </div>
  );
};

import { SynthParameters } from '../types';

interface ActiveNote {
  osc1: OscillatorNode;
  osc2: OscillatorNode;
  osc3: OscillatorNode;
  osc4: OscillatorNode;
  osc1Gain: GainNode;
  osc2Gain: GainNode;
  osc3Gain: GainNode;
  osc4Gain: GainNode;
  lfoOsc: OscillatorNode;
  lfoGain: GainNode;
  filter: BiquadFilterNode;
  filterEnvSource: ConstantSourceNode; // Generates the ADSR shape (0 to 1)
  filterEnvGain: GainNode; // Scales the ADSR shape by 'amount'
  amp: GainNode;
  tremoloGain: GainNode;
  lfoTarget: string;
  velocity: number; // Store normalized velocity (0-1)
}

export class AudioEngine {
  private audioContext: AudioContext | null = null;
  private activeNotes = new Map<number, ActiveNote>();
  private params: SynthParameters;

  constructor(initialParams: SynthParameters) {
    this.params = initialParams;
  }

  public async start() {
    if (this.audioContext && this.audioContext.state === 'running') {
      return;
    }
    this.audioContext = new AudioContext();
    if (this.audioContext.state === 'suspended') {
      await this.audioContext.resume();
    }
  }

  public getContext(): AudioContext | null {
      return this.audioContext;
  }

  public updateParams(newParams: SynthParameters) {
    // Check if LFO targets or timing changed significantly enough to warrant re-triggering? 
    // Usually for LFO Delay/Fade we only apply it on Note On. Live changes to delay/fade usually don't affect running notes.
    // However, live changes to Rate/Depth should.

    this.params = newParams;
    if (!this.audioContext) return;

    const now = this.audioContext.currentTime;
    // Update params for all currently playing notes
    for (const note of this.activeNotes.values()) {
        // --- Oscillators ---
        if (note.osc1.type !== this.params.osc1.waveform) note.osc1.type = this.params.osc1.waveform;
        if (note.osc2.type !== this.params.osc2.waveform) note.osc2.type = this.params.osc2.waveform;
        if (note.osc3.type !== this.params.osc3.waveform) note.osc3.type = this.params.osc3.waveform;
        if (note.osc4.type !== this.params.osc4.waveform) note.osc4.type = this.params.osc4.waveform;

        note.osc1.detune.setValueAtTime(this.params.osc1.detune, now);
        note.osc2.detune.setValueAtTime(this.params.osc2.detune, now);
        note.osc3.detune.setValueAtTime(this.params.osc3.detune, now);
        note.osc4.detune.setValueAtTime(this.params.osc4.detune, now);

        const masterHeadroom = 0.25;
        note.osc1Gain.gain.setTargetAtTime(this.params.osc1.enabled ? this.params.osc1.gain * masterHeadroom : 0, now, 0.01);
        note.osc2Gain.gain.setTargetAtTime(this.params.osc2.enabled ? this.params.osc2.gain * masterHeadroom : 0, now, 0.01);
        note.osc3Gain.gain.setTargetAtTime(this.params.osc3.enabled ? this.params.osc3.gain * masterHeadroom : 0, now, 0.01);
        note.osc4Gain.gain.setTargetAtTime(this.params.osc4.enabled ? this.params.osc4.gain * masterHeadroom : 0, now, 0.01);

        // --- Filter ---
        // Update Base Cutoff
        note.filter.frequency.setTargetAtTime(this.params.filter.cutoff, now, 0.01);
        note.filter.Q.setTargetAtTime(this.params.filter.resonance, now, 0.01);

        // Update Envelope Amount - Scale by the note's velocity
        // If we don't multiply by velocity here, tweaking the knob live would jump the filter 
        // to full intensity even on a soft note.
        note.filterEnvGain.gain.setTargetAtTime(this.params.filterEnvelope.amount * note.velocity, now, 0.01);

        // --- LFO ---
        // Update basic LFO params
        if (note.lfoOsc.type !== this.params.lfo.waveform) note.lfoOsc.type = this.params.lfo.waveform;
        note.lfoOsc.frequency.setTargetAtTime(this.params.lfo.rate, now, 0.01);

        // Handle Target Switching
        if (note.lfoTarget !== this.params.lfo.target) {
            note.lfoGain.disconnect();
            this.connectLfoToTarget(note, this.params.lfo.target, now);
            note.lfoTarget = this.params.lfo.target;
        } else {
             // Just update depth if target hasn't changed.
             this.updateLfoDepth(note, this.params.lfo.target, now);
        }
    }
  }

  private connectLfoToTarget(note: ActiveNote, target: string, time: number) {
      if (target === 'pitch') {
          note.lfoGain.connect(note.osc1.detune);
          note.lfoGain.connect(note.osc2.detune);
          note.lfoGain.connect(note.osc3.detune);
          note.lfoGain.connect(note.osc4.detune);
      } else if (target === 'filter') {
          note.lfoGain.connect(note.filter.detune); 
      } else if (target === 'amp') {
          note.lfoGain.connect(note.tremoloGain.gain);
      }
      this.updateLfoDepth(note, target, time);
  }

  private updateLfoDepth(note: ActiveNote, target: string, time: number) {
      let maxGain = 0;
      const depth = this.params.lfo.depth;

      if (target === 'pitch') maxGain = depth * 1200;
      else if (target === 'filter') maxGain = depth * 4800;
      else if (target === 'amp') maxGain = depth * 0.5;

      note.lfoGain.gain.setTargetAtTime(maxGain, time, 0.1);
  }

  private midiToFrequency(note: number): number {
    return 440 * Math.pow(2, (note - 69) / 12);
  }

  public noteOn(note: number, velocity: number = 127) {
    if (!this.audioContext) return;

    if (this.activeNotes.has(note)) {
      this.noteOff(note);
    }

    const now = this.audioContext.currentTime;
    const frequency = this.midiToFrequency(note);
    const velocityGain = velocity / 127;

    // --- Audio Graph ---

    // Amp Section
    const tremoloGain = this.audioContext.createGain();
    tremoloGain.gain.setValueAtTime(1, now);
    tremoloGain.connect(this.audioContext.destination);

    const amp = this.audioContext.createGain();
    amp.gain.setValueAtTime(0, now);
    amp.connect(tremoloGain);

    // Filter Section
    const filter = this.audioContext.createBiquadFilter();
    filter.type = 'lowpass';
    filter.Q.setValueAtTime(this.params.filter.resonance, now);
    // Base Cutoff
    filter.frequency.setValueAtTime(this.params.filter.cutoff, now);
    filter.connect(amp);

    // Filter Envelope Generation
    // We use a ConstantSourceNode to generate the 0-1 ADSR curve
    const filterEnvSource = this.audioContext.createConstantSource();
    filterEnvSource.offset.setValueAtTime(0, now);
    filterEnvSource.start(now);

    const filterEnvGain = this.audioContext.createGain();
    // Scale filter envelope amount by velocity
    filterEnvGain.gain.setValueAtTime(this.params.filterEnvelope.amount * velocityGain, now);

    filterEnvSource.connect(filterEnvGain);
    filterEnvGain.connect(filter.frequency);

    // Oscillators
    const masterHeadroom = 0.25;
    const createOsc = (params: any) => {
        const osc = this.audioContext!.createOscillator();
        osc.type = params.waveform;
        osc.frequency.setValueAtTime(frequency, now);
        osc.detune.setValueAtTime(params.detune, now);

        const gain = this.audioContext!.createGain();
        const targetGain = params.enabled ? params.gain * masterHeadroom : 0;
        gain.gain.setValueAtTime(targetGain, now);

        osc.connect(gain).connect(filter);
        osc.start(now);
        return { osc, gain };
    };

    const osc1Obj = createOsc(this.params.osc1);
    const osc2Obj = createOsc(this.params.osc2);
    const osc3Obj = createOsc(this.params.osc3);
    const osc4Obj = createOsc(this.params.osc4);

    // --- LFO Setup ---
    const lfoOsc = this.audioContext.createOscillator();
    lfoOsc.type = this.params.lfo.waveform;
    lfoOsc.frequency.setValueAtTime(this.params.lfo.rate, now);

    const lfoGain = this.audioContext.createGain();

    // Calculate LFO Max Depth Value
    let maxLfoDepthVal = 0;
    if (this.params.lfo.target === 'pitch') maxLfoDepthVal = this.params.lfo.depth * 1200;
    else if (this.params.lfo.target === 'filter') maxLfoDepthVal = this.params.lfo.depth * 4800;
    else if (this.params.lfo.target === 'amp') maxLfoDepthVal = this.params.lfo.depth * 0.5;

    // Schedule LFO Delay and Fade
    const delayTime = this.params.lfo.delay;
    const fadeTime = this.params.lfo.fade;

    lfoGain.gain.setValueAtTime(0, now);
    lfoGain.gain.setValueAtTime(0, now + delayTime);
    if (fadeTime > 0) {
        lfoGain.gain.linearRampToValueAtTime(maxLfoDepthVal, now + delayTime + fadeTime);
    } else {
        lfoGain.gain.setValueAtTime(maxLfoDepthVal, now + delayTime);
    }

    lfoOsc.connect(lfoGain);
    lfoOsc.start(now);

    const activeNote: ActiveNote = { 
        osc1: osc1Obj.osc, osc1Gain: osc1Obj.gain,
        osc2: osc2Obj.osc, osc2Gain: osc2Obj.gain,
        osc3: osc3Obj.osc, osc3Gain: osc3Obj.gain,
        osc4: osc4Obj.osc, osc4Gain: osc4Obj.gain,
        lfoOsc, lfoGain, tremoloGain,
        filter, filterEnvSource, filterEnvGain, amp,
        lfoTarget: this.params.lfo.target,
        velocity: velocityGain // Store for updates
    };

    // Connect LFO based on current target
    if (this.params.lfo.target === 'pitch') {
        lfoGain.connect(osc1Obj.osc.detune);
        lfoGain.connect(osc2Obj.osc.detune);
        lfoGain.connect(osc3Obj.osc.detune);
        lfoGain.connect(osc4Obj.osc.detune);
    } else if (this.params.lfo.target === 'filter') {
        lfoGain.connect(filter.detune);
    } else if (this.params.lfo.target === 'amp') {
        lfoGain.connect(tremoloGain.gain);
    }

    // --- Amp Envelope Schedule ---
    const { attack: ampAttack, decay: ampDecay, sustain: ampSustain } = this.params.ampEnvelope;
    const peakAmp = velocityGain;
    const sustainAmp = peakAmp * ampSustain;
    amp.gain.linearRampToValueAtTime(peakAmp, now + ampAttack);
    amp.gain.linearRampToValueAtTime(sustainAmp, now + ampAttack + ampDecay);

    // --- Filter Envelope Schedule ---
    // Note: base cutoff is already set on filter.frequency.
    // We only modulate the ConstantSourceNode (0 to 1)
    const { attack: filterAttack, decay: filterDecay, sustain: filterSustain } = this.params.filterEnvelope;

    // offset starts at 0
    filterEnvSource.offset.linearRampToValueAtTime(1, now + filterAttack); // Peak at 1 (full amount)
    filterEnvSource.offset.linearRampToValueAtTime(filterSustain, now + filterAttack + filterDecay); // Sustain Level

    this.activeNotes.set(note, activeNote);
  }

  public noteOff(note: number) {
    if (!this.audioContext || !this.activeNotes.has(note)) {
      return;
    }

    const n = this.activeNotes.get(note)!;
    this.activeNotes.delete(note);

    const now = this.audioContext.currentTime;

    // Amp Release
    const { release: ampRelease } = this.params.ampEnvelope;
    n.amp.gain.cancelScheduledValues(now);
    n.amp.gain.setValueAtTime(n.amp.gain.value, now);
    n.amp.gain.linearRampToValueAtTime(0, now + ampRelease);

    // Filter Envelope Release
    const { release: filterRelease } = this.params.filterEnvelope;
    n.filterEnvSource.offset.cancelScheduledValues(now);
    n.filterEnvSource.offset.setValueAtTime(n.filterEnvSource.offset.value, now);
    n.filterEnvSource.offset.linearRampToValueAtTime(0, now + filterRelease);

    const stopTime = now + Math.max(ampRelease, filterRelease);
    n.osc1.stop(stopTime);
    n.osc2.stop(stopTime);
    n.osc3.stop(stopTime);
    n.osc4.stop(stopTime);
    n.lfoOsc.stop(stopTime);
    n.filterEnvSource.stop(stopTime);

    // Garbage collection
    n.osc1.onended = () => {
      n.osc1.disconnect();
      n.osc2.disconnect();
      n.osc3.disconnect();
      n.osc4.disconnect();
      n.lfoOsc.disconnect();
      n.lfoGain.disconnect();
      n.filter.disconnect();
      n.filterEnvSource.disconnect();
      n.filterEnvGain.disconnect();
      n.amp.disconnect();
      n.tremoloGain.disconnect();
    };
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SynthParameters, Waveform, StepSequencePattern, DrumTrackName, LFOTarget } from '../types';
import { AudioEngine } from '../services/AudioEngine';
import { DrumMachineEngine } from '../services/DrumMachineEngine';
import { Knob } from './Knob';
import { Keyboard } from './Keyboard';
import { DrumMachine } from './DrumMachine';
import { DEFAULT_SYNTH_PARAMS, DEFAULT_BPM, DEFAULT_DRUM_PATTERN } from '../constants';
import { SineIcon, SawtoothIcon, SquareIcon, TriangleIcon } from './Icon';
import { WaveformDisplay } from './WaveformDisplay';

interface PanelProps {
  title: string;
  children: React.ReactNode;
  className?: string;
}

const Panel: React.FC<PanelProps> = ({ title, children, className = "" }) => (
  <div className={`relative bg-[#1a1a1a] rounded-sm border border-[#333] p-6 flex flex-col items-center shadow-xl ${className}`}>
    {/* Hardware Screw aesthetic */}
    <div className="absolute top-2 left-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-45"></div></div>
    <div className="absolute top-2 right-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-12"></div></div>
    <div className="absolute bottom-2 left-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-90"></div></div>
    <div className="absolute bottom-2 right-2 w-2 h-2 rounded-full bg-[#111] border border-[#222] flex items-center justify-center shadow-inner opacity-50"><div className="w-full h-[1px] bg-[#333] rotate-[-45deg]"></div></div>

    <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mb-6 border-b border-gray-700 pb-1 px-2">{title}</h3>
    {children}
  </div>
);

export const Synth: React.FC = () => {
  const [params, setParams] = useState<SynthParameters>(DEFAULT_SYNTH_PARAMS);
  const [midiStatus, setMidiStatus] = useState<string>('Not initialized. Click to start.');
  const [isStarted, setIsStarted] = useState(false);
  const [activeNotes, setActiveNotes] = useState<Set<number>>(new Set());

  // Drum Machine State
  const [banks, setBanks] = useState<StepSequencePattern[]>(() => 
    Array(4).fill(null).map(() => JSON.parse(JSON.stringify(DEFAULT_DRUM_PATTERN)))
  );
  const [currentBankIndex, setCurrentBankIndex] = useState<number>(0);
  const drumPattern = banks[currentBankIndex];

  const [selectedTrack, setSelectedTrack] = useState<DrumTrackName>('kick');
  const [isDrumMachinePlaying, setIsDrumMachinePlaying] = useState(false);
  const [bpm, setBpm] = useState(DEFAULT_BPM);
  const [swing, setSwing] = useState(0);
  const [drumPitches, setDrumPitches] = useState<Record<DrumTrackName, number>>({
      kick: 0,
      snare: 0,
      hihat: 0,
      crash: 0
  });
  const [currentStep, setCurrentStep] = useState<number | null>(null);

  const audioEngine = useRef<AudioEngine | null>(null);
  const drumMachineEngine = useRef<DrumMachineEngine | null>(null);

  const handleStart = useCallback(async () => {
    if (isStarted) return;

    const engine = new AudioEngine(DEFAULT_SYNTH_PARAMS);
    await engine.start();
    const audioContext = engine.getContext();
    if (!audioContext) {
        setMidiStatus('Failed to initialize Audio Context.');
        return;
    }
    audioEngine.current = engine;

    drumMachineEngine.current = new DrumMachineEngine(audioContext, (step) => setCurrentStep(step));
    drumMachineEngine.current.setPattern(drumPattern);
    drumMachineEngine.current.setSwing(swing);
    Object.entries(drumPitches).forEach(([track, pitch]) => {
        drumMachineEngine.current?.setTrackPitch(track as DrumTrackName, pitch);
    });

    setIsStarted(true);
    setMidiStatus('Initializing MIDI...');

    try {
      const midiAccess = await navigator.requestMIDIAccess();
      setMidiStatus('MIDI Access Granted');

      if (midiAccess.inputs.size > 0) {
        const devices: string[] = [];
        midiAccess.inputs.forEach((input) => {
          devices.push(input.name || 'Unknown Device');
          input.onmidimessage = (e) => handleMidiMessage(e);
        });
        setMidiStatus(`Connected to: ${devices.join(', ')}`);
      } else {
        setMidiStatus('No MIDI input devices found.');
      }

      midiAccess.onstatechange = (event: Event) => {
          const port = (event as MIDIConnectionEvent).port;
          if (port.type === 'input') {
              const deviceName = port.name || 'Unknown Device';
              if (port.state === 'connected') {
                  setMidiStatus(`MIDI device connected: ${deviceName}`);
              } else {
                  setMidiStatus(`MIDI device disconnected: ${deviceName}`);
              }
          }
      };

    } catch (error) {
      console.error('MIDI Access Denied:', error);
      setMidiStatus('MIDI access denied by user.');
    }
  }, [isStarted]);

  useEffect(() => {
    if (audioEngine.current) {
      audioEngine.current.updateParams(params);
    }
  }, [params]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setBpm(bpm);
      }
  }, [bpm]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setSwing(swing);
      }
  }, [swing]);

  useEffect(() => {
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setPattern(drumPattern);
      }
  }, [drumPattern]);

  const handleDrumPitchChange = (val: number) => {
      const newPitches = { ...drumPitches, [selectedTrack]: val };
      setDrumPitches(newPitches);
      if (drumMachineEngine.current) {
          drumMachineEngine.current.setTrackPitch(selectedTrack, val);
      }
  };

  const handleStepToggle = (track: DrumTrackName, stepIndex: number) => {
    const newBanks = [...banks];
    const currentPattern = { ...newBanks[currentBankIndex] };
    const newTrackPattern = [...currentPattern[track]];

    const isOn = newTrackPattern[stepIndex] === 0;
    newTrackPattern[stepIndex] = isOn ? 1 : 0;

    currentPattern[track] = newTrackPattern;
    newBanks[currentBankIndex] = currentPattern;

    setBanks(newBanks);

    if (isOn && drumMachineEngine.current) {
      drumMachineEngine.current.playSound(track);
    }
  };


  const handleMidiMessage = (message: MIDIMessageEvent) => {
    if (!audioEngine.current) return;

    // Check if the message comes from a button press (which might send an array directly) or a real MIDI event
    const data = message.data;
    if (!data) return;

    const [status, data1, data2] = data;
    const command = status & 0xf0; // Mask channel
    // const channel = status & 0x0f;

    if (command === 144 && data2 > 0) { // Note On
      audioEngine.current.noteOn(data1, data2);
      setActiveNotes(prev => new Set(prev).add(data1));
    } else if (command === 128 || (command === 144 && data2 === 0)) { // Note Off
      audioEngine.current.noteOff(data1);
      setActiveNotes(prev => {
        const newSet = new Set(prev);
        newSet.delete(data1);
        return newSet;
      });
    } else if (command === 176) { // Control Change
      // Mapping MIDI CC to synth parameters
      // CC 74: Brightness/Cutoff
      if (data1 === 74) {
         // Map 0-127 to 20-20000 Hz logarithmically
         const min = 20;
         const max = 20000;
         const normalized = data2 / 127;
         const cutoff = min * Math.pow(max / min, normalized);
         setParams(p => ({ ...p, filter: { ...p.filter, cutoff: cutoff } }));
      }
      // CC 1: Modulation Wheel -> LFO Depth
      else if (data1 === 1) {
         const depth = data2 / 127;
         setParams(p => ({ ...p, lfo: { ...p.lfo, depth: depth } }));
      }
    }
  };

  const handleNoteOn = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOn(note, 100);
    setActiveNotes(prev => new Set(prev).add(note));
  };

  const handleNoteOff = (note: number) => {
    if (!isStarted || !audioEngine.current) return;
    audioEngine.current.noteOff(note);
    setActiveNotes(prev => {
      const newSet = new Set(prev);
      newSet.delete(note);
      return newSet;
    });
  };

  const setOscWaveform = (osc: 'osc1' | 'osc2' | 'osc3' | 'osc4', waveform: Waveform) => {
    setParams(p => ({ ...p, [osc]: { ...p[osc], waveform } }));
  };

  const toggleOsc = (osc: 'osc1' | 'osc2' | 'osc3' | 'osc4') => {
      setParams(p => ({...p, [osc]: {...p[osc], enabled: !p[osc].enabled } }));
  }

  const setLfoWaveform = (waveform: Waveform) => {
      setParams(p => ({ ...p, lfo: { ...p.lfo, waveform } }));
  };

  const handlePlayToggle = () => {
      if (!drumMachineEngine.current) return;
      const nextIsPlaying = !isDrumMachinePlaying;
      setIsDrumMachinePlaying(nextIsPlaying);
      if (nextIsPlaying) {
          drumMachineEngine.current.play();
      } else {
          drumMachineEngine.current.stop();
          setCurrentStep(null);
      }
  };

  const renderOscControl = (oscKey: 'osc1' | 'osc2' | 'osc3' | 'osc4', label: string) => {
      const oscParams = params[oscKey];
      return (
        <div className="flex flex-col gap-2 border border-[#222] p-2 rounded-sm bg-[#111] w-full relative">
            <div className="flex items-center gap-2 mb-1 w-full justify-between px-1 border-b border-[#222] pb-1">
                <span className="text-gray-500 text-[10px] font-mono tracking-widest">{label}</span>
                {/* Red Light Toggle */}
                <button 
                    onClick={() => toggleOsc(oscKey)}
                    className={`w-3 h-3 rounded-full transition-all duration-300 border border-red-900 ${oscParams.enabled ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,1)]' : 'bg-[#300] shadow-inner'}`}
                    aria-label={`Toggle ${label}`}
                />
            </div>

            <div className="flex flex-row items-stretch w-full gap-4 px-1">
                 {/* Vertical Waveform Icons */}
                <div className="flex flex-col gap-1 bg-[#0a0a0a] p-1 rounded-sm border border-[#222] h-full justify-between w-8 shrink-0">
                    {(['sine', 'triangle', 'sawtooth', 'square'] as Waveform[]).map(w => {
                        const isActive = oscParams.waveform === w;
                        const Icon = { sine: SineIcon, triangle: TriangleIcon, sawtooth: SawtoothIcon, square: SquareIcon }[w];
                        return (
                        <button 
                            key={w} 
                            onClick={() => setOscWaveform(oscKey, w)} 
                            className={`p-1 rounded-sm transition-all duration-100 flex items-center justify-center h-6
                                ${isActive 
                                    ? 'bg-[#333] text-white shadow-[0_0_5px_rgba(255,255,255,0.2)] border border-gray-600' 
                                    : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                                }`}
                        >
                            <Icon className="w-4 h-4"/>
                        </button>
                        );
                    })}
                </div>

                {/* Middle Section: LCD Display, Visualizer, Volume */}
                <div className="flex flex-col flex-1 justify-between gap-1 min-w-[80px]">
                    {/* LCD Display - Smaller height */}
                    <div className="bg-[#081008] border border-[#222] rounded-sm px-1 py-0.5 shadow-inner flex items-center justify-center h-5 w-full overflow-hidden">
                        <span className="font-mono text-[#44ff44] text-[9px] tracking-widest uppercase opacity-80">
                            {oscParams.waveform}
                        </span>
                    </div>

                    {/* Visualizer */}
                    <div className="flex-1 w-full min-h-[36px] my-0.5">
                        <WaveformDisplay 
                          waveform={oscParams.waveform} 
                          isPlaying={oscParams.enabled} 
                          amplitudeScale={oscParams.gain}
                        />
                    </div>

                    {/* Volume Slider */}
                     <div className="flex flex-col w-full px-1">
                        <div className="flex justify-between items-end mb-1">
                             <label className="text-[8px] text-gray-500 uppercase font-mono leading-none">Vol</label>
                             <span className="text-[8px] text-gray-400 font-mono leading-none">{Math.round(oscParams.gain * 100)}</span>
                        </div>
                        <input
                            type="range"
                            min="0"
                            max="1"
                            step="0.01"
                            value={oscParams.gain}
                            onChange={(e) => setParams(p => ({ ...p, [oscKey]: { ...p[oscKey], gain: parseFloat(e.target.value) } }))}
                            className="w-full h-1.5 bg-[#222] rounded-lg appearance-none cursor-pointer accent-white"
                        />
                    </div>
                </div>

                {/* Right Section: Pitch Knob */}
                 <div className="flex items-center justify-center border-l border-[#222] pl-3">
                    <Knob 
                        label="Pitch" 
                        value={oscParams.detune} 
                        min={-2400} 
                        max={2400} 
                        size={32}
                        onChange={v => setParams(p => ({ ...p, [oscKey]: { ...p[oscKey], detune: v } }))} 
                    />
                 </div>
            </div>
        </div>
      );
  };

  if (!isStarted) {
    return (
        <div className="flex flex-col items-center justify-center bg-[#1a1a1a] border border-[#333] rounded-sm p-16 shadow-2xl">
            <h2 className="text-2xl font-bold text-white mb-2 tracking-wider">SYSTEM STANDBY</h2>
            <p className="text-gray-500 mb-8 font-mono text-xs">{midiStatus}</p>
            <button
                onClick={handleStart}
                className="px-8 py-3 bg-[#222] text-gray-200 border border-gray-600 font-bold text-sm tracking-widest rounded-sm hover:bg-gray-200 hover:text-black hover:border-white transition-all duration-200 shadow-lg"
            >
                INITIALIZE ENGINE
            </button>
        </div>
    );
  }

  return (
    <div className="space-y-8">

      {/* Top Section: Oscillators, Filter, Envelopes */}
      <div className="flex flex-col xl:flex-row gap-8 items-stretch">

        {/* Left: Oscillators */}
        <Panel title="VCO" className="flex-1 justify-center">
             <div className="flex flex-col gap-6 py-2 w-full max-w-2xl">
                {/* 2x2 Grid for Oscillators */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pb-2">
                    {renderOscControl('osc1', 'OSC 1')}
                    {renderOscControl('osc2', 'OSC 2')}
                    {renderOscControl('osc3', 'OSC 3')}
                    {renderOscControl('osc4', 'OSC 4')}
                </div>
            </div>
        </Panel>

        {/* Right: Filter & Envelopes Group & LFO */}
        <div className="flex flex-col sm:flex-row gap-8 shrink-0 xl:w-[500px]">

            <div className="flex flex-col gap-8 sm:w-1/3">
                 {/* Filter */}
                <Panel title="VCF" className="flex-1 justify-between">
                    <div className="flex flex-col gap-6 h-full justify-center py-2">
                        {/* Logarithmic Cutoff for better feel */}
                        <Knob label="Cutoff" value={params.filter.cutoff} min={20} max={20000} logarithmic onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, cutoff: v } }))} />
                        <Knob label="Resonance" value={params.filter.resonance} min={0} max={40} onChange={v => setParams(p => ({ ...p, filter: { ...p.filter, resonance: v } }))} />
                        {/* Increased EG Int max for stronger modulation effect */}
                        <Knob label="EG Int" value={params.filterEnvelope.amount} min={0} max={20000} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, amount: v } }))} />
                    </div>
                </Panel>
            </div>


            {/* Envelopes & LFO */}
            <div className="flex flex-col gap-8 sm:w-2/3">
                <Panel title="LFO" className="justify-center">
                    <div className="flex flex-col gap-3 w-full">
                         <div className="flex flex-row items-stretch w-full gap-4">
                            {/* LFO Waveform Buttons */}
                             <div className="flex flex-col gap-1 bg-[#0a0a0a] p-1 rounded-sm border border-[#222] justify-between">
                                {(['sine', 'triangle', 'sawtooth', 'square'] as Waveform[]).map(w => {
                                    const isActive = params.lfo.waveform === w;
                                    const Icon = { sine: SineIcon, triangle: TriangleIcon, sawtooth: SawtoothIcon, square: SquareIcon }[w];
                                    return (
                                    <button 
                                        key={w} 
                                        onClick={() => setLfoWaveform(w)} 
                                        className={`p-1.5 rounded-sm transition-all duration-100 flex items-center justify-center flex-1
                                            ${isActive 
                                                ? 'bg-[#333] text-white shadow-[0_0_5px_rgba(255,255,255,0.2)] border border-gray-600' 
                                                : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                                            }`}
                                    >
                                        <Icon className="w-3 h-3"/>
                                    </button>
                                    );
                                })}
                            </div>

                            {/* Middle: LFO Visualizer */}
                            <div className="flex flex-col flex-1 justify-between gap-1 min-w-[60px]">
                                {/* LCD */}
                                <div className="bg-[#081008] border border-[#222] rounded-sm px-1 py-0.5 shadow-inner flex items-center justify-center h-5 w-full overflow-hidden">
                                    <span className="font-mono text-[#4488ff] text-[9px] tracking-widest uppercase opacity-80">
                                        {params.lfo.waveform}
                                    </span>
                                </div>
                                {/* Visualizer */}
                                <div className="flex-1 w-full min-h-[40px] my-0.5">
                                    <WaveformDisplay 
                                        waveform={params.lfo.waveform} 
                                        isPlaying={activeNotes.size > 0}
                                        amplitudeScale={params.lfo.depth}
                                        color="#3b82f6" // Blue
                                    />
                                </div>
                            </div>

                            {/* Controls - Grid for compactness */}
                            <div className="grid grid-cols-2 gap-2">
                                 <Knob label="Rate" value={params.lfo.rate} min={0.1} max={20} size={36} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, rate: v } }))} />
                                 <Knob label="Depth" value={params.lfo.depth} min={0} max={1} size={36} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, depth: v } }))} />
                                 <Knob label="Delay" value={params.lfo.delay} min={0} max={2} size={36} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, delay: v } }))} />
                                 <Knob label="Fade" value={params.lfo.fade} min={0} max={2} size={36} onChange={v => setParams(p => ({ ...p, lfo: { ...p.lfo, fade: v } }))} />
                            </div>
                         </div>

                        {/* Target Selector */}
                        <div className="flex items-center gap-2 text-[9px] font-mono uppercase tracking-wide border-t border-[#333] pt-2 w-full justify-center">
                            <span className="text-gray-500 mr-2">Target:</span>
                            {(['pitch', 'filter', 'amp'] as LFOTarget[]).map(target => (
                                <button
                                    key={target}
                                    onClick={() => setParams(p => ({ ...p, lfo: { ...p.lfo, target: target } }))}
                                    className={`px-2 py-0.5 rounded-sm transition-colors ${
                                        params.lfo.target === target 
                                        ? 'bg-[#333] text-white' 
                                        : 'text-gray-600 hover:text-gray-400 hover:bg-[#222]'
                                    }`}
                                >
                                    {target}
                                </button>
                            ))}
                        </div>
                    </div>
                </Panel>

                <Panel title="AMP EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        <Knob label="Attack" value={params.ampEnvelope.attack} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.ampEnvelope.decay} min={0.001} max={2} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.ampEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, sustain: v } }))} />
                        <Knob label="Release" value={params.ampEnvelope.release} min={0.001} max={5} onChange={v => setParams(p => ({ ...p, ampEnvelope: { ...p.ampEnvelope, release: v } }))} />
                    </div>
                </Panel>

                <Panel title="FILTER EG" className="flex-1 justify-center">
                    <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
                        {/* Finer control for Attack and Decay (max 1s) */}
                        <Knob label="Attack" value={params.filterEnvelope.attack} min={0.001} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, attack: v } }))} />
                        <Knob label="Decay" value={params.filterEnvelope.decay} min={0.001} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, decay: v } }))} />
                        <Knob label="Sustain" value={params.filterEnvelope.sustain} min={0} max={1} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, sustain: v } }))} />
                        {/* Extended Release range (max 10s) */}
                        <Knob label="Release" value={params.filterEnvelope.release} min={0.001} max={10} onChange={v => setParams(p => ({ ...p, filterEnvelope: { ...p.filterEnvelope, release: v } }))} />
                    </div>
                </Panel>
            </div>
        </div>

      </div>

      <DrumMachine
        isPlaying={isDrumMachinePlaying}
        onPlayToggle={handlePlayToggle}
        bpm={bpm}
        onBpmChange={setBpm}
        pattern={drumPattern}
        selectedTrack={selectedTrack}
        onTrackSelect={setSelectedTrack}
        onStepToggle={handleStepToggle}
        currentStep={currentStep}
        currentBank={currentBankIndex}
        onBankSelect={setCurrentBankIndex}
        swing={swing}
        onSwingChange={setSwing}
        trackPitch={drumPitches[selectedTrack]}
        onTrackPitchChange={handleDrumPitchChange}
       />

      <div className="bg-[#1a1a1a] rounded-sm border-t-4 border-[#111] shadow-2xl">
        <Keyboard onNoteOn={handleNoteOn} onNoteOff={handleNoteOff} activeNotes={activeNotes} />
        <div className="bg-[#0a0a0a] text-center text-[10px] text-gray-600 py-1 font-mono uppercase tracking-widest">{midiStatus}</div>
      </div>
    </div>
  );
};
